"use client";

/**
 * ChatPortal
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 * Renders the ChatFAB and ChatWidget into a dedicated DOM node
 * so they always float on top of every page without being
 * clipped by overflow:hidden ancestors.
 *
 * Mount this ONCE inside DashboardLayoutContent alongside the
 * other system-level components (VilletoTourGuide, etc.).
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 */

import { useEffect, useState } from "react";
import { createPortal } from "react-dom";
import { ChatFAB } from "./ChatFAB";
import { ChatWidget } from "./ChatWidget";

export function ChatPortal() {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  return createPortal(
    <>
      <ChatWidget />
      <ChatFAB />
    </>,
    document.body
  );
}

"use client";

/**
 * ChatWidget
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 * The main chat panel that slides in from the bottom-right.
 * Renders one of three views based on state:
 *
 *  1. Contact list  ΓÇö Team / Vendors tab with search
 *  2. Vendor inbox  ΓÇö Thread list for a selected vendor
 *  3. Conversation  ΓÇö Active chat thread
 *
 * Multiple conversations can be open simultaneously; each is
 * rendered as a stacked panel accessible via the conversations
 * stack in the store.
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 */

import { useState, useEffect } from "react";
import { AnimatePresence, motion } from "framer-motion";
import { useChatStore, Vendor, TeamMember, Conversation } from "@/stores/useChatStore";
import { ChatConversationPanel } from "./ChatConversationPanel";
import { cn } from "@/lib/utils";
import {
  Messages2,
  SearchNormal1,
  Profile,
  Building,
  Add,
} from "iconsax-reactjs";
import { X } from "lucide-react";

// ΓöÇΓöÇΓöÇ Mock data (remove when API is wired) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const MOCK_TEAM: TeamMember[] = [
  { id: "u1", name: "Sunday Israel", role: "Design manager", code: "E-001" },
  { id: "u2", name: "Amara Okonkwo", role: "Finance lead", code: "E-002" },
  { id: "u3", name: "Bode Adeyemi", role: "Procurement officer", code: "E-003" },
  { id: "u4", name: "Chisom Eze", role: "Operations manager", code: "E-004" },
  { id: "u5", name: "Damilola Alabi", role: "HR manager", code: "E-005" },
];

const MOCK_VENDORS: Vendor[] = [
  {
    id: "v1",
    name: "ABC Supplies Ltd",
    code: "E-001",
    unreadCount: 2,
    threads: [
      { id: "t1", label: "PO-1043" },
      { id: "t2", label: "PO-1098" },
      { id: "t3", label: "INV-2033" },
      { id: "t4", label: "Delivery Confirmation DC-442" },
      { id: "t5", label: "General" },
    ],
  },
  {
    id: "v2",
    name: "TechSolutions Inc.",
    code: "E-001",
    threads: [
      { id: "t6", label: "PO-2210" },
      { id: "t7", label: "General" },
    ],
  },
  {
    id: "v3",
    name: "Tools & Co",
    code: "E-001",
    threads: [
      { id: "t8", label: "PO-3301" },
      { id: "t9", label: "General" },
    ],
  },
];
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type PanelView =
  | { type: "list" }
  | { type: "vendor-inbox"; vendor: Vendor }
  | { type: "conversation"; convId: string };

export function ChatWidget() {
  const {
    isOpen,
    closeChat,
    activeTab,
    setActiveTab,
    teamSearch,
    vendorSearch,
    setTeamSearch,
    setVendorSearch,
    teamMembers,
    vendors,
    setTeamMembers,
    setVendors,
    conversations,
    openConversation,
  } = useChatStore();

  const [panelView, setPanelView] = useState<PanelView>({ type: "list" });

  // Load mock data on mount (replace with API calls)
  useEffect(() => {
    if (teamMembers.length === 0) setTeamMembers(MOCK_TEAM);
    if (vendors.length === 0) setVendors(MOCK_VENDORS);
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Reset to list when widget closes
  useEffect(() => {
    if (!isOpen) setPanelView({ type: "list" });
  }, [isOpen]);

  // ΓöÇΓöÇΓöÇ Filtered lists ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const filteredTeam = teamMembers.filter(
    (m) =>
      m.name.toLowerCase().includes(teamSearch.toLowerCase()) ||
      m.role.toLowerCase().includes(teamSearch.toLowerCase())
  );

  const filteredVendors = vendors.filter((v) =>
    v.name.toLowerCase().includes(vendorSearch.toLowerCase())
  );

  // ΓöÇΓöÇΓöÇ Open team conversation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const openTeamConv = (member: TeamMember) => {
    const convId = `team-${member.id}`;
    openConversation({
      id: convId,
      tab: "team",
      participantId: member.id,
      participantName: member.name,
      participantRole: member.role,
      participantCode: member.code,
    });
    setPanelView({ type: "conversation", convId });
  };

  // ΓöÇΓöÇΓöÇ Open vendor inbox ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const openVendorInbox = (vendor: Vendor) => {
    setPanelView({ type: "vendor-inbox", vendor });
  };

  // ΓöÇΓöÇΓöÇ Open vendor thread ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const openVendorThread = (vendor: Vendor, threadId: string) => {
    const thread = vendor.threads.find((t) => t.id === threadId);
    const convId = `vendor-${vendor.id}-${threadId}`;
    openConversation({
      id: convId,
      tab: "vendors",
      participantId: vendor.id,
      participantName: vendor.name,
      participantCode: vendor.code,
      thread,
      availableThreads: vendor.threads,
    });
    setPanelView({ type: "conversation", convId });
  };

  // ΓöÇΓöÇΓöÇ Start new vendor conversation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const startNewVendorConversation = (vendor: Vendor) => {
    const convId = `vendor-${vendor.id}-new-${Date.now()}`;
    openConversation({
      id: convId,
      tab: "vendors",
      participantId: vendor.id,
      participantName: vendor.name,
      participantCode: vendor.code,
      availableThreads: vendor.threads,
    });
    setPanelView({ type: "conversation", convId });
  };

  // ΓöÇΓöÇΓöÇ Active conversation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const activeConv =
    panelView.type === "conversation"
      ? conversations.find((c) => c.id === panelView.convId)
      : null;

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          key="chat-widget"
          initial={{ opacity: 0, y: 24, scale: 0.97 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          exit={{ opacity: 0, y: 24, scale: 0.97 }}
          transition={{ type: "spring", stiffness: 400, damping: 30 }}
          className={cn(
            "fixed bottom-20 right-6 z-50",
            "w-[360px] h-[580px]",
            "bg-white rounded-2xl shadow-2xl border border-gray-100",
            "flex flex-col overflow-hidden"
          )}
          style={{ boxShadow: "0 8px 40px rgba(0,0,0,0.14)" }}
        >
          {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
          <div className="flex items-center gap-3 px-4 pt-4 pb-3 border-b border-gray-100 flex-shrink-0">
            <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center">
              <Messages2 size={16} className="text-primary" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-semibold text-gray-900">Messages</p>
              <p className="text-[11px] text-gray-500">Communication centre</p>
            </div>
            <button
              onClick={closeChat}
              className="text-gray-400 hover:text-gray-600 transition-colors"
              aria-label="Close chat"
            >
              <X size={16} />
            </button>
          </div>

          {/* ΓöÇΓöÇ Tabs (always visible on list view) ΓöÇΓöÇ */}
          {(panelView.type === "list" || panelView.type === "vendor-inbox") && (
            <div className="flex border-b border-gray-100 flex-shrink-0">
              <TabButton
                active={activeTab === "team"}
                onClick={() => {
                  setActiveTab("team");
                  setPanelView({ type: "list" });
                }}
                icon={<Profile size={14} />}
                label="Team"
              />
              <TabButton
                active={activeTab === "vendors"}
                onClick={() => {
                  setActiveTab("vendors");
                  setPanelView({ type: "list" });
                }}
                icon={<Building size={14} />}
                label="Vendors"
              />
            </div>
          )}

          {/* ΓöÇΓöÇ Body ΓöÇΓöÇ */}
          <div className="flex-1 overflow-hidden flex flex-col">
            <AnimatePresence mode="wait">
              {/* Contact / vendor list */}
              {panelView.type === "list" && (
                <motion.div
                  key="list"
                  initial={{ opacity: 0, x: -8 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -8 }}
                  className="flex-1 flex flex-col overflow-hidden"
                >
                  {/* Search */}
                  <div className="px-4 py-3 flex-shrink-0">
                    <div className="flex items-center gap-2 bg-gray-50 rounded-xl px-3 py-2">
                      <SearchNormal1 size={14} className="text-gray-400 flex-shrink-0" />
                      <input
                        type="text"
                        placeholder={
                          activeTab === "team"
                            ? "Search employees..."
                            : "Search vendors..."
                        }
                        className="flex-1 text-sm bg-transparent outline-none text-gray-800 placeholder:text-gray-400"
                        value={activeTab === "team" ? teamSearch : vendorSearch}
                        onChange={(e) =>
                          activeTab === "team"
                            ? setTeamSearch(e.target.value)
                            : setVendorSearch(e.target.value)
                        }
                      />
                    </div>
                  </div>

                  {/* List */}
                  <div className="flex-1 overflow-y-auto px-4 pb-4">
                    {activeTab === "team" ? (
                      <>
                        {filteredTeam.length === 0 && (
                          <p className="text-sm text-gray-400 text-center mt-8">
                            No team members found
                          </p>
                        )}
                        {filteredTeam.map((member) => (
                          <TeamMemberRow
                            key={member.id}
                            member={member}
                            onClick={() => openTeamConv(member)}
                            conversation={conversations.find(
                              (c) => c.id === `team-${member.id}`
                            )}
                          />
                        ))}
                      </>
                    ) : (
                      <>
                        {filteredVendors.length === 0 && (
                          <p className="text-sm text-gray-400 text-center mt-8">
                            No vendors found
                          </p>
                        )}
                        {filteredVendors.map((vendor) => (
                          <VendorRow
                            key={vendor.id}
                            vendor={vendor}
                            onClick={() => openVendorInbox(vendor)}
                          />
                        ))}
                      </>
                    )}
                  </div>
                </motion.div>
              )}

              {/* Vendor inbox (thread list) */}
              {panelView.type === "vendor-inbox" && (
                <motion.div
                  key="vendor-inbox"
                  initial={{ opacity: 0, x: 8 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: 8 }}
                  className="flex-1 flex flex-col overflow-hidden"
                >
                  <VendorInboxPanel
                    vendor={panelView.vendor}
                    conversations={conversations}
                    onBack={() => setPanelView({ type: "list" })}
                    onOpenThread={(threadId) =>
                      openVendorThread(panelView.vendor, threadId)
                    }
                    onNewConversation={() =>
                      startNewVendorConversation(panelView.vendor)
                    }
                  />
                </motion.div>
              )}

              {/* Active conversation */}
              {panelView.type === "conversation" && activeConv && (
                <motion.div
                  key={`conv-${panelView.convId}`}
                  initial={{ opacity: 0, x: 8 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: 8 }}
                  className="flex-1 flex flex-col overflow-hidden"
                >
                  <ChatConversationPanel
                    conversation={activeConv}
                    onBack={() => {
                      if (activeConv.tab === "vendors") {
                        const vendor = vendors.find(
                          (v) => v.id === activeConv.participantId
                        );
                        if (vendor) {
                          setPanelView({ type: "vendor-inbox", vendor });
                          return;
                        }
                      }
                      setPanelView({ type: "list" });
                    }}
                  />
                </motion.div>
              )}

              {/* Conversation closed / not found */}
              {panelView.type === "conversation" && !activeConv && (
                <div className="flex-1 flex items-center justify-center">
                  <p className="text-sm text-gray-400">Conversation not found.</p>
                </div>
              )}
            </AnimatePresence>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
}

// ΓöÇΓöÇΓöÇ Sub-components ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

