type SortField = 'merchant' | 'date' | 'cardholder' | 'department' | 'location' | 'amount';
type SortDirection = 'asc' | 'desc';

export function TransactionTable() {
    const [sortField, setSortField] = useState<SortField>('date');
    const [sortDirection, setSortDirection] = useState<SortDirection>('desc');

    const handleSort = (field: SortField) => {
        if (sortField === field) {
            setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
        } else {
            setSortField(field);
            setSortDirection('asc');
        }
    };

    const sortedTransactions = [...transactions].sort((a, b) => {
        let aValue: string | number = '';
        let bValue: string | number = '';

        switch (sortField) {
            case 'merchant':
                aValue = a.merchant;
                bValue = b.merchant;
                break;
            case 'date':
                aValue = new Date(a.date).getTime();
                bValue = new Date(b.date).getTime();
                break;
            case 'cardholder':
                aValue = a.cardholder;
                bValue = b.cardholder;
                break;
            case 'department':
                aValue = a.department;
                bValue = b.department;
                break;
            case 'location':
                aValue = a.location;
                bValue = b.location;
                break;
            case 'amount':
                aValue = parseFloat(a.amount.replace('$', ''));
                bValue = parseFloat(b.amount.replace('$', ''));
                break;
        }

        if (typeof aValue === 'string' && typeof bValue === 'string') {
            return sortDirection === 'asc'
                ? aValue.localeCompare(bValue)
                : bValue.localeCompare(aValue);
        } else {
            return sortDirection === 'asc'
                ? (aValue as number) - (bValue as number)
                : (bValue as number) - (aValue as number);
        }
    });

    const SortableHeader = ({ field, children }: { field: SortField; children: React.ReactNode }) => (
        <TableHead
            className={`cursor-pointer hover:bg-dashboard-hover select-none ${field === 'amount' ? 'text-right' : ''}`}
            onClick={() => handleSort(field)}
        >
            <div className="flex items-center gap-1">
