import { useState } from "react";
import {
    useReactTable,
    getCoreRowModel,
    getSortedRowModel,
    getFilteredRowModel,
    getPaginationRowModel,
    flexRender,
    SortingState,
    ColumnDef,
} from "@tanstack/react-table";
import { Card } from "@/components/ui/card";
import { Checkbox } from "@/components/ui/checkbox";
import { Button } from "@/components/ui/button";
import { AlertTriangle, MoreHorizontal, RefreshCw } from "lucide-react";


import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";

type PolicyAlert = {
    id: string;
    name: string;
    department: string;
    alert: "High" | "Medium" | "Low";
    date: string;
};

const data: PolicyAlert[] = [
    { id: "0001", name: "Stephen Abubakar", department: "Design & Development", alert: "High", date: "26-09-2025" },
    { id: "0002", name: "Stephen Abubakar", department: "Design & Development", alert: "Medium", date: "26-09-2025" },
    { id: "0003", name: "Stephen Abubakar", department: "Design & Development", alert: "Medium", date: "26-09-2025" },
    { id: "0004", name: "Sarah Johnson", department: "Marketing", alert: "Low", date: "25-09-2025" },
    { id: "0005", name: "Mike Chen", department: "Engineering", alert: "High", date: "24-09-2025" },
];

export const PolicyAlertsTable = () => {
    const [sorting, setSorting] = useState<SortingState>([]);
    const [globalFilter, setGlobalFilter] = useState("");
    const [rowSelection, setRowSelection] = useState({});
    const [columnFilters, setColumnFilters] = useState<unknown>([]);

    const columns: ColumnDef<PolicyAlert>[] = [
        {
            id: "select",
            header: () => null,
            cell: ({ row }) => (
                <Checkbox
                    checked={row.getIsSelected()}
                    onCheckedChange={(value) => row.toggleSelected(!!value)}
                />
            ),
            enableSorting: false,
        },
        {
            accessorKey: "id",
            header: () => "ID NO",
        },
        {
            accessorKey: "name",
            header: () => "NAME OF EMPLOYEE",
        },
        {
            accessorKey: "department",
            header: () => "DEPARTMENT",
        },
        {
            accessorKey: "alert",
            header: () => "POLICY ALERT",
            cell: ({ row }) => {
                const alert = row.getValue("alert") as string;
                return (
                    <div className="flex items-center gap-2">
                        <AlertTriangle
                            className={`w-4 h-4 ${alert === "High" ? "text-destructive" :
                                alert === "Medium" ? "text-warning" :
                                    "text-muted-foreground"
                                }`}
                        />
                        <span className={`text-sm ${alert === "High" ? "text-destructive" :
                            alert === "Medium" ? "text-warning" :
                                "text-muted-foreground"
                            }`}>
                            {alert}
                        </span>
                    </div>
                );
            },
        },
        {
            accessorKey: "date",
            header: () => "DATE",
        },
        {
            id: "actions",
            header: "ACTION",
            cell: () => (
                <Button variant="ghost" size="sm">
                    <MoreHorizontal className="w-4 h-4" />
                </Button>
            ),
        },
    ];

    const table = useReactTable({
        data,
        columns,
        state: {
            sorting,
            globalFilter,
            rowSelection,
            columnFilters,
        },
        onSortingChange: setSorting,
        onGlobalFilterChange: setGlobalFilter,
        onRowSelectionChange: setRowSelection,
        onColumnFiltersChange: setColumnFilters,
        getCoreRowModel: getCoreRowModel(),
        getSortedRowModel: getSortedRowModel(),
        getFilteredRowModel: getFilteredRowModel(),
        getPaginationRowModel: getPaginationRowModel(),
    });

    return (
        <Card className="p-6 rounded-[14px] border">
            <div className="flex items-center justify-between mb-4">
                <div>
                    <h3 className="text-lg font-semibold leading-[100%]">Policy Alerts</h3>
                    <p className="text-sm text-muted-foreground mt-2">Your latest policy alerts</p>
                </div>
                <Button variant="ghost" size="sm">
                    <RefreshCw className="w-4 h-4" />
                </Button>
            </div>

            <div className="rounded-md border">
                <Table>
                    <TableHeader>
                        {table.getHeaderGroups().map((headerGroup) => (
                            <TableRow key={headerGroup.id} className="bg-muted/50">
                                {headerGroup.headers.map((header) => (
                                    <TableHead key={header.id}>
                                        {header.isPlaceholder
                                            ? null
                                            : flexRender(
                                                header.column.columnDef.header,
                                                header.getContext()
                                            )}
                                    </TableHead>
                                ))}
                            </TableRow>
                        ))}
                    </TableHeader>
                    <TableBody>
                        {table.getRowModel().rows?.length ? (
                            table.getRowModel().rows.map((row) => (
                                <TableRow key={row.id} data-state={row.getIsSelected() && "selected"}>
                                    {row.getVisibleCells().map((cell) => (
                                        <TableCell key={cell.id}>
                                            {flexRender(cell.column.columnDef.cell, cell.getContext())}
                                        </TableCell>
                                    ))}
                                </TableRow>
                            ))
                        ) : (
                            <TableRow>
                                <TableCell colSpan={columns.length} className="h-24 text-center">
                                    No results.
                                </TableCell>
                            </TableRow>
                        )}
                    </TableBody>
                </Table>
            </div>
        </Card>
    );
};

"use client";

/**
 * DashboardLayoutContent
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 * Changed (Setup Guide update):
 *  ΓÇó Imports and mounts <VilletoSetupGuide /> alongside the
 *    existing <VilletoTourGuide />.
 *  ΓÇó VilletoTourGuide excludes Setup Guide users internally,
 *    so both can coexist without conflict.
 * ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
 */

import { DashboardSidebar } from "@/components/dashboard/sidebar/DashboardSidebar";
import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";
import { UserSection } from "@/components/user/user-section";
import { useEffect, useState } from "react";
import { useAuthStore, User } from "@/stores/auth-stores";
import { useAxios } from "@/hooks/useAxios";
import { usePathname, useRouter } from "next/navigation";
import DashboardModals from "@/components/dashboard/layout/DashboardModals";
import VilletoTourGuide from "@/components/tour/VilletoTourGuide";
import VilletoSetupGuide from "@/components/tour/VilletoSetupGuide";
import { useTourStore } from "@/stores/useTourStore";
import { ChatPortal } from "@/components/chat";

interface DashboardLayoutProps {
  children: React.ReactNode;
  defaultOpen?: boolean;
}

export default function DashboardLayoutContent({
  children,
  defaultOpen = false,
}: DashboardLayoutProps) {
  const [isMounted, setIsMounted] = useState(false);
  const axios = useAxios();
  const { setCompanyPermissions, login, user, isLoading } = useAuthStore();
  const router = useRouter();
  const pathname = usePathname();
  const isTourActive = useTourStore((s) => s.isTourActive);

  useEffect(() => {
    setIsMounted(true);

    // Lock body scroll to prevent double scrollbars in dashboard
    document.documentElement.style.overflow = "hidden";
    document.body.style.overflow = "hidden";

    return () => {
      document.documentElement.style.overflow = "";
      document.body.style.overflow = "";
    };
  }, []);

  // Refreshes the current user's profile and permissions from the server.
  // Called on initial mount, periodically, and on window focus, so that
  // permission changes made by an admin mid-session (e.g. a role downgrade)
  // take effect without requiring the user to log out and back in.
  const refreshUserAndPermissions = async () => {
    try {
      const me = await axios.get("/users/me");
      const responseData = me?.data?.data || me?.data;
      const { role, _company, companyId, ...userData } = responseData || {};

      if (userData) {
        const currentUser = useAuthStore.getState().user;
        const userWithCompany = {
          ...currentUser,
          ...userData,
          companyId: companyId || userData.companyId || currentUser?.companyId,
        };
        login(userWithCompany as User);
      }

      if (role || responseData?.companyRole) {
        const permissions = responseData?.companyRole?.permissions ?? role?.permissions ?? [];
        setCompanyPermissions(permissions);
      }
    } catch {
      // Silently handle ΓÇö user session may still be valid
    }
  };

  useEffect(() => {
    if (isLoading) return;

    if (!user) {
      router.push("/login");
      return;
    }

    refreshUserAndPermissions();

    // Periodically re-check permissions every 5 minutes so role/permission
    // changes made by an admin propagate without requiring re-login.
    const interval = setInterval(refreshUserAndPermissions, 5 * 60 * 1000);

    // Also refresh when the tab regains focus ΓÇö covers the common case of
    // an admin changing a user's role in another tab/session while this
    // tab was inactive.
    const onFocus = () => refreshUserAndPermissions();
    window.addEventListener("focus", onFocus);

    return () => {
      clearInterval(interval);
      window.removeEventListener("focus", onFocus);
    };
  }, [isLoading]); // eslint-disable-line react-hooks/exhaustive-deps

  if (!isMounted) {
    return (
      <div className="flex h-screen bg-dashboard-background" suppressHydrationWarning>
        <div className="flex-1 flex flex-col overflow-hidden" suppressHydrationWarning />
      </div>
    );
  }

  return (
    <div className="flex bg-dashboard-background h-screen overflow-hidden" suppressHydrationWarning>
      <SidebarProvider defaultOpen={defaultOpen}>
        <DashboardSidebar />
        <div className="flex flex-col flex-1 h-full overflow-hidden">
          <header className="flex items-center gap-4 px-6 h-16 border-b border-dashboard-border-shade w-full flex-shrink-0">
            {/* Hide mobile collapse trigger during tour so sidebar stays open */}
            {!isTourActive && <SidebarTrigger className="md:hidden" />}
            <UserSection />
          </header>

          <main className="flex-1 overflow-y-auto p-5" key={pathname}>
            {children}
          </main>
        </div>
      </SidebarProvider>

      {/* System-level modals (force-password reset, etc.) */}
      <DashboardModals />

      {/*
       * VilletoTourGuide ΓÇö informational tour for all users EXCEPT
       * those who qualify for the interactive Setup Guide.
       * (Exclusion is handled inside VilletoTourGuide itself.)
       */}
      <VilletoTourGuide />

      {/*
       * VilletoSetupGuide ΓÇö interactive workspace-setup flow for
       * CONTROLLING_OFFICER / ORGANIZATION_OWNER users on first login.
       * Activates AFTER SetPasswordModal closes (via setupGuideReady flag).
       */}
      <VilletoSetupGuide />
      <ChatPortal />
    </div>
  );
}

