"use client";
import { cn } from "@/lib/utils";
import { ChevronRight } from "lucide-react";
import Link from "next/link";
import Image from "next/image";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import { useEffect, useState } from "react";
import { useTourStore } from "@/stores/useTourStore";
import { useQuery } from "@tanstack/react-query";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarMenuSubButton,
  SidebarTrigger,
  useSidebar,
} from "@/components/ui/sidebar";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "../../ui/collapsible";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { useAuthStore } from "@/stores/auth-stores";
import { Logout } from "iconsax-reactjs";
import { NavItem, navigationItems } from "./sidebar-constants";
import { useAxios } from "@/hooks/useAxios";
import { Skeleton } from "@/components/ui/skeleton";
import { logger } from "@/lib/logger";

export function DashboardSidebar() {
  const location = usePathname();
  const searchParams = useSearchParams();
  const [expandedMenus, setExpandedMenus] = useState<string[]>(() => {
    if (typeof window !== "undefined") {
      const p = window.location.pathname;
      if (p.startsWith("/expenses"))    return ["Expenses"];
      if (p.startsWith("/procurement")) return ["Procurement"];
      if (p.startsWith("/settings"))    return ["Settings"];
    }
    return [];
  });

  const logout = useAuthStore((state) => state.logout);
  const can = useAuthStore((state) => state.can);
  const user = useAuthStore((state) => state.user);
  const router = useRouter();
  const axios = useAxios();
  const { state, setOpen } = useSidebar();
  const isTourActive = useTourStore((s) => s.isTourActive);

  const [showLogoutModal, setShowLogoutModal] = useState(false);

  // ΓöÇΓöÇ Force sidebar open for the entire duration of the tour ΓöÇΓöÇ
  useEffect(() => {
    if (isTourActive) {
      setOpen(true);
    }
  }, [isTourActive, state, setOpen]);

  // Auto-expand the correct sidebar section when navigating
  useEffect(() => {
    if (location.startsWith("/expenses"))    setExpandedMenus(prev => prev.includes("Expenses")    ? prev : [...prev, "Expenses"]);
    if (location.startsWith("/procurement")) setExpandedMenus(prev => prev.includes("Procurement") ? prev : [...prev, "Procurement"]);
    if (location.startsWith("/settings"))    setExpandedMenus(prev => prev.includes("Settings")    ? prev : [...prev, "Settings"]);
  }, [location]);

  const { data: companyData, isLoading: isQueryLoading } = useQuery({
    queryKey: ["company", user?.companyId, user?.userId],
    queryFn: async () => {
      if (!user?.userId) return null;
      if (user.companyId) {
        try {
          const res = await axios.get(`/companies/${user.companyId}`);
          const data = res?.data?.data || res?.data;
          if (data) return data;
        } catch (error) {
          logger.error("Primary company fetch failed:", error);
        }
      }
      try {
        const fall = await axios.get("/users/me");
        return fall?.data?.data?.company || fall?.data?.company || null;
      } catch (err) {
        logger.error("Fallback /users/me fetch failed:", err);
        return null;
      }
    },
    enabled: !!user?.userId,
    staleTime: 1000 * 60 * 60, // 1 hour caching to persist efficiently
  });

  const businessLogo = companyData?.logoUrl ?? user?.company?.logoUrl ?? null;
  const businessName = companyData?.companyName ?? companyData?.businessName ?? user?.company?.companyName ?? user?.company?.businessName ?? null;
  const loading = isQueryLoading && !businessLogo && !businessName;

  const toggleMenu = (label: string) => {
    setExpandedMenus((prev) =>
      prev.includes(label)
        ? prev.filter((item) => item !== label)
        : [...prev, label],
    );
  };

  const isActive = (href: string) => {
    // Strip query parameters for active state matching
    const basePath = href.split("?")[0];
    if (basePath === "/dashboard") {
      return location === basePath;
    }

    if (location === "/settings/personal-settings") {
      const activeTab = searchParams.get("tab");
      if (basePath === "/settings/company-settings") {
        return activeTab === "company-profile";
      }
      if (basePath === "/settings/personal-settings") {
        return activeTab === "my-profile" || !activeTab;
      }
    }

    if (basePath === "/expenses") {
      if (
        location.startsWith("/expenses/reimbursements") ||
        location.startsWith("/expenses/card-transactions") ||
        location.startsWith("/expenses/travel")
      ) {
        return false;
      }
      return location.startsWith(basePath);
    }

    return location.startsWith(basePath);
  };

  // A nav item (or sub-item) is visible if its permissions list is empty
  // (always visible) OR the user satisfies at least one of the listed gates.
  const hasNavPermission = (permissions: NavItem["permissions"]): boolean => {
    if (!permissions || permissions.length === 0) return true;
    return permissions.some(p => can(p.resource, p.action));
  };

  const canViewCompanyExpenses =
    can('expense.report', 'read_company') || can('expense.report', 'read_department');

  const filterItems = (items: NavItem[]): NavItem[] => {
    return items
      .map((item) => {
        const currentItem = { ...item };

        // Append default tab query param for Expenses based on user capability
        if (currentItem.href === "/expenses") {
          currentItem.href = canViewCompanyExpenses
            ? "/expenses?tab=company-expenses"
            : "/expenses?tab=personal-expenses";
        }

        if (currentItem.subItems) {
          const filteredSubs = currentItem.subItems
            .map((sub) => {
              const currentSub = { ...sub };
              if (currentSub.label === "All Expenses") {
                if (!canViewCompanyExpenses) {
                  currentSub.label = "My Expenses";
                }
                currentSub.href = canViewCompanyExpenses
                  ? "/expenses?tab=company-expenses"
                  : "/expenses?tab=personal-expenses";
              }
              return currentSub;
            })
            .filter((sub) => hasNavPermission(sub.permissions));

          // Show the parent if it has its own permission OR at least one visible sub
          if (!hasNavPermission(currentItem.permissions) && filteredSubs.length === 0)
            return null;
          currentItem.subItems = filteredSubs;
          return currentItem;
        } else {
          if (!hasNavPermission(currentItem.permissions)) return null;
          return currentItem;
        }
      })
      .filter(Boolean) as NavItem[];
  };
  const filteredNavigationItems = filterItems(navigationItems);
  const renderLogo = () => {
    if (loading) return <Skeleton className="w-full h-full rounded-full" />;
    if (businessLogo)
      return (
        <Image
          src={businessLogo}
          alt="Business Logo"
          width={36}
          height={36}
          className="w-full h-full object-contain"
          unoptimized={
            businessLogo.startsWith("data:") || businessLogo.startsWith("http")
          }
        />
      );
    return (
      <div className="w-full h-full rounded-full bg-dashboard-accent/10 flex items-center justify-center shrink-0">
        <span className="text-sm font-semibold text-dashboard-accent">
          {businessName?.charAt(0).toUpperCase() || "B"}
        </span>
      </div>
    );
  };
  const renderCollapsedLogo = () => {
    if (loading) return <Skeleton className="w-10 h-10 rounded-full" />;
    if (businessLogo)
      return (
        <Image
          src={businessLogo}
          alt={businessName || "Business Logo"}
          width={40}
          height={40}
          className="w-10 h-10 object-contain rounded-full"
          unoptimized={
            businessLogo.startsWith("data:") || businessLogo.startsWith("http")
          }
        />
      );
    return (
      <div className="w-10 h-10 rounded-full bg-dashboard-accent/10 flex items-center justify-center shrink-0">
        <span className="text-lg font-semibold text-dashboard-accent">
          {businessName?.charAt(0).toUpperCase() || "B"}
        </span>
      </div>
    );
  };
  const renderMenuItem = (item: NavItem) => {
    const hasExpandable = item.subItems && item.subItems.length > 0;
    if (hasExpandable) {
      const isOpen = expandedMenus.includes(item.label);
      const isGroupActive = item.subItems?.some(sub => sub.href && isActive(sub.href)) || isActive(item.href);
      return (
        <SidebarMenuItem key={item.label}>
          <Collapsible
            open={isOpen}
            onOpenChange={() => toggleMenu(item.label)}
          >
            <CollapsibleTrigger asChild>
              <SidebarMenuButton
                tooltip={item.label}
                isActive={isGroupActive}
                className="font-normal text-sm text-[#7F7F7F] data-[active=true]:text-primary data-[active=true]:bg-sidebar-accent data-[active=true]:font-medium"
              >
                <span className="shrink-0 [&>svg]:size-5 [&>svg]:shrink-0">
                  {item.icon}
                </span>
                <span className="group-data-[collapsible=icon]:hidden">{item.label}</span>
                <ChevronRight
                  className={cn(
                    "ml-auto h-4 w-4 transition-transform duration-200 group-data-[collapsible=icon]:hidden",
                    isOpen && "rotate-90",
                  )}
                />
              </SidebarMenuButton>
            </CollapsibleTrigger>
            <CollapsibleContent className="mt-1 space-y-1 pl-8 group-data-[collapsible=icon]:hidden">
              {item.subItems?.map((sub) => {
                if (sub.comingSoon) {
                  return (
                    <span
                      key={sub.label}
                      className="flex items-center justify-between w-full px-2 py-1.5 text-xs opacity-50 cursor-not-allowed"
                    >
                      <span>{sub.label}</span>
                      <span className="ml-auto bg-amber-100 text-amber-700 px-1.5 py-0.5 rounded-full text-[9px] font-semibold whitespace-nowrap">
                        Coming Soon
                      </span>
                    </span>
                  );
                }
                return (
                  <SidebarMenuSubButton
                    key={sub.label}
                    asChild
                    isActive={isActive(sub.href!)}
                    className={cn(
                      "text-xs",
                      isActive(sub.href!) &&
                        "bg-sidebar-accent/20 font-medium text-primary",
                    )}
                  >
                    <Link href={sub.href!} className="flex items-center justify-between w-full">
                      <span>{sub.label}</span>
                      {sub.badge && (
                          <span className="ml-auto bg-[#F4F0FF] text-[#6941C6] px-2 py-0.5 rounded-full text-[10px] font-medium whitespace-nowrap">
                              {sub.badge}
                          </span>
                      )}
                      {sub.imageUrl === "user-avatar" && (
                          (user as unknown)?.profilePicture ? (
                              <img src={(user as unknown).profilePicture} alt="Avatar" className="ml-auto w-5 h-5 rounded-full object-cover" />
                          ) : (
                              <div className="ml-auto w-5 h-5 rounded-full bg-gray-200 flex items-center justify-center text-[10px] font-medium text-gray-600 capitalize">
                                  {user?.firstName?.[0] || user?.email?.[0] || "U"}
                              </div>
                          )
                      )}
                    </Link>
                  </SidebarMenuSubButton>
                );
              })}
            </CollapsibleContent>
          </Collapsible>
        </SidebarMenuItem>
      );
    }
    if (!item.href) return null;
    // Coming Soon items: render as span, not link
    if (item.comingSoon) {
      return (
        <SidebarMenuItem key={item.label}>
          <SidebarMenuButton
            tooltip={item.label}
            className="opacity-50 cursor-not-allowed hover:bg-transparent hover:text-[#7F7F7F]"
          >
            <span className="shrink-0 [&>svg]:size-5 [&>svg]:shrink-0">{item.icon}</span>
            <span className="group-data-[collapsible=icon]:hidden flex-1">{item.label}</span>
            <span className="ml-auto bg-amber-100 text-amber-700 px-2 py-0.5 rounded-full text-[10px] font-semibold group-data-[collapsible=icon]:hidden whitespace-nowrap">
              Coming Soon
            </span>
          </SidebarMenuButton>
        </SidebarMenuItem>
      );
    }
    return (
      <SidebarMenuItem key={item.label}>
        <SidebarMenuButton
          asChild
          isActive={isActive(item.href)}
          tooltip={item.label}
          className="font-normal text-sm text-[#7F7F7F] data-[active=true]:text-primary data-[active=true]:bg-sidebar-accent data-[active=true]:font-medium"
        >
          <Link href={item.href}>
            <span className="shrink-0 [&>svg]:size-5 [&>svg]:shrink-0">{item.icon}</span>
            <span className="group-data-[collapsible=icon]:hidden">{item.label}</span>
          </Link>
        </SidebarMenuButton>
      </SidebarMenuItem>
    );
  };
  return (
    <Sidebar collapsible="icon" className="border-r border-sidebar-border">
      <SidebarHeader className="w-full border-b border-sidebar-border px-0! py-0! space-y-0">
        <div className="flex flex-col">
          {/* Villeto Logo + Toggle - Fixed height h-16 (64px) to match main header border line */}
          <div
            className={cn(
              "flex items-center h-16 border-b border-sidebar-border transition-all duration-300",
              state === "expanded" ? "justify-between px-4" : "justify-center",
            )}
          >
            {state === "expanded" ? (
              <>
                <Link
                  href="/dashboard"
                  className="flex items-center cursor-pointer hover:opacity-80 transition-opacity"
                >
                  <Image
                    src="/images/villeto-logo.png"
                    alt="Villeto Logo"
                    width={90}
                    height={28}
                    className="h-auto max-h-7 object-contain"
                    priority
                  />
                </Link>
                {/* Hide collapse trigger while tour is active */}
                {!isTourActive && <SidebarTrigger className="shrink-0 cursor-pointer" />}
              </>
            ) : (
              /* Hide collapse trigger while tour is active */
              !isTourActive && <SidebarTrigger className="shrink-0 cursor-pointer" />
            )}
          </div>
          {/* Company Selector - placed below the primary header alignment line */}
          <div
            className={cn(
              "flex items-center transition-all duration-300 px-3 py-1",
              state === "expanded" ? "" : "justify-center",
            )}
          >
            {state === "expanded" ? (
              <div className="w-full flex items-center bg-muted rounded-lg px-3 my-1 gap-3 h-10">
                <div className=" flex items-center justify-center shrink-0 w-6 h-6 overflow-hidden">
                  {renderLogo()}
                </div>
                <span className="flex-1 text-sm font-medium text-dashboard-text-primary truncate">
                  {loading ? (
                    <Skeleton className="h-5 w-40" />
                  ) : (
                    businessName || "Business Name"
                  )}
                </span>
                <ChevronRight className="w-4 h-4 text-gray-500 shrink-0" />
              </div>
            ) : (
              <div className="flex items-center justify-center w-6 h-6 my-2">
                {renderCollapsedLogo()}
              </div>
            )}
          </div>
        </div>
      </SidebarHeader>
      <SidebarContent className="py-4">
        <SidebarMenu className="space-y-1 px-3">
          {filteredNavigationItems.map((item) => renderMenuItem(item))}
        </SidebarMenu>
      </SidebarContent>
      <SidebarFooter className="border-t border-sidebar-border px-3 py-2">
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton
              onClick={() => setShowLogoutModal(true)}
              tooltip="Log Out"
              className="font-normal text-sm text-[#7F7F7F] hover:text-destructive hover:bg-sidebar-accent"
            >
              <Logout className="size-5 shrink-0" />
              <span className="group-data-[collapsible=icon]:hidden">Log Out</span>
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarFooter>

      <AlertDialog open={showLogoutModal} onOpenChange={setShowLogoutModal}>
        <AlertDialogContent className="z-[9999]">
          <AlertDialogHeader>
            <AlertDialogTitle>Are you sure you want to log out?</AlertDialogTitle>
            <AlertDialogDescription>
              Any unsaved changes may be lost. You will need to log in again to access the dashboard.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction
              className="bg-red-500 hover:bg-red-600 text-white"
              onClick={() => {
                logout();
                router.push("/login");
              }}
            >
              Log Out
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </Sidebar>
  );
}

"use client";

import React, {
  useMemo,
  useCallback,
  useState,
  useEffect,
  type JSX,
} from "react";
import { usePathname, useRouter, useSearchParams } from "next/navigation";
import {
  useReactTable,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  getPaginationRowModel,
  type ColumnDef,
  type TableOptions,
  type PaginationState,
  type SortingState,
  type RowSelectionState,
  type ColumnFiltersState,
  type VisibilityState,
} from "@tanstack/react-table";
// import MyLoader from "../loader-components";
import exportCSV from "@/lib/exportCSV";
import { ITableHeader, TableHeader } from "./tableHeader";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "../ui/select";
import {
  Pagination,
  PaginationContent,
  PaginationEllipsis,
  PaginationItem,
  PaginationLink,
  PaginationNext,
  PaginationPrevious,
} from "../ui/pagination";
import { Checkbox } from "../ui/checkbox";
import {
  Table,
  TableHeader as TableHead,
  TableBody,
  TableRow,
  TableCell,
} from "../ui/table";
import { Skeleton } from "@/components/ui/skeleton";

const PAGE_SIZE_OPTIONS = [
  { label: "5", value: "5" },
  { label: "10", value: "10" },
  { label: "20", value: "20" },
  { label: "30", value: "30" },
  { label: "40", value: "40" },
  { label: "50", value: "50" },
  { label: "100", value: "100" },
];

export type DataTableProps<Data extends object, Value = unknown> = {
  data: Data[];
  columns: ColumnDef<Data, Value>[];
  paginationProps?: {
    page: number;
    pageSize: number;
    total: number;
    setPage: (e: number) => void;
    setPageSize: (e: number) => void;
  };
  tableProps?: Partial<TableOptions<Data>>;
  isLoading?: boolean;
  manualPagination?: boolean;
  manualSorting?: boolean;
  manualFiltering?: boolean;
  initialSorting?: SortingState;
  initialColumnFilters?: ColumnFiltersState;
  initialColumnVisibility?: VisibilityState;
  height?: string | number;
  tableHeader?: ITableHeader;
  selectedDataIds?: Set<string>;
  setSelectedDataIds?: (selection: Set<string>) => void;
  enableRowSelection?: boolean;
  enableColumnVisibility?: boolean;
  getRowId?: (row: Data) => string;
  onSortingChange?: (sorting: SortingState) => void;
  onColumnFiltersChange?: (filters: ColumnFiltersState) => void;
  onRowSelectionChange?: (selection: RowSelectionState) => void;
  onColumnVisibilityChange?: (visibility: VisibilityState) => void;
  onRowClick?: (row: Data) => void;
};

function DataTable<Data extends object, Value = unknown>(
  props: DataTableProps<Data, Value> & {
    onSearch?: (query: string) => void;
    onFilter?: (filters: Record<string, unknown>) => void;
    showCreateBulkButton?: boolean;
    onCreateBulk?: () => void;
  }
): JSX.Element {
  const {
    data,
    columns,
    paginationProps,
    tableProps,
    isLoading,
    manualPagination = false,
    manualSorting = false,
    manualFiltering = false,
    _height = "400px",
    initialSorting = [],
    initialColumnFilters = [],
    initialColumnVisibility = {},
    tableHeader,
    selectedDataIds = new Set(),
    setSelectedDataIds,
    enableRowSelection = false,
    enableColumnVisibility = false,
    getRowId = (row: unknown) => row.id || row._id,
    _onSortingChange,
    _onColumnFiltersChange,
    onRowSelectionChange,
    onColumnVisibilityChange,
    onRowClick,
  } = props;

  const [sorting, setSorting] = useState<SortingState>(initialSorting);
  const [columnFilters, _setColumnFilters] =
    useState<ColumnFiltersState>(initialColumnFilters);
  const [columnVisibility, setColumnVisibility] = useState<VisibilityState>(initialColumnVisibility);
  const [rowSelection, setRowSelection] = useState<RowSelectionState>({});

  // Navigation context for conditional row click behavior
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const isExpensesIndex = pathname === "/expenses";
  const currentTab = searchParams?.get("tab") ?? null;
  const expensesClickMode = isExpensesIndex
    ? currentTab === "personal-expenses"
      ? "personal"
      : "company"
    : null;

  // Derive scope for company expense row-click navigation
  const expensesScope = currentTab === "team-expenses" ? "team" : "company";

  const memoizedColumns = useMemo(() => columns, [columns]);
  const memoizedData = useMemo(() => data, [data]);

  // Create select column for multi-select
  const selectColumn = enableRowSelection
    ? {
        id: "select",
        header: ({ table }: unknown) => (
          <Checkbox
            checked={
              table.getIsAllPageRowsSelected() ||
              (table.getIsSomePageRowsSelected() && "indeterminate")
            }
            onCheckedChange={(value) =>
              table.toggleAllPageRowsSelected(!!value)
            }
            aria-label="Select all"
          />
        ),
        cell: ({ row }: unknown) => (
          <Checkbox
            checked={row.getIsSelected()}
            onCheckedChange={(value) => row.toggleSelected(!!value)}
            aria-label="Select row"
          />
        ),
        enableSorting: false,
        enableHiding: false,
      }
    : null;

  const allColumns = useMemo(() => {
    return selectColumn ? [selectColumn, ...memoizedColumns] : memoizedColumns;
  }, [selectColumn, memoizedColumns]);

  const pagination = useMemo<PaginationState>(
    () => ({
      pageIndex: paginationProps ? paginationProps.page - 1 : 0,
      pageSize: paginationProps?.pageSize || 10,
    }),
    [paginationProps?.page, paginationProps?.pageSize]
  );

  const table = useReactTable({
    columns: allColumns,
    data: memoizedData,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    state: {
      sorting,
      pagination,
      columnFilters,
      columnVisibility,
      rowSelection,
    },
    manualPagination,
    manualSorting,
    manualFiltering,
    onSortingChange: setSorting,
    onColumnVisibilityChange: (updater) => {
      const newVisibility =
        typeof updater === "function" ? updater(columnVisibility) : updater;
      setColumnVisibility(newVisibility);
      onColumnVisibilityChange?.(newVisibility);
    },
    onRowSelectionChange: (updater) => {
      const newSelection =
        typeof updater === "function" ? updater(rowSelection) : updater;
      setRowSelection(newSelection);
      onRowSelectionChange?.(newSelection);
    },
    enableRowSelection: enableRowSelection,
    enableColumnFilters: true,
    pageCount: paginationProps
      ? Math.ceil(paginationProps.total / pagination.pageSize)
      : -1,
    ...tableProps,
  });

  const _rowModel = table.getRowModel();

  // Get selected data for bulk actions
  const selectedData = useMemo(() => {
    return data.filter((row) => selectedDataIds.has(getRowId(row)));
  }, [data, selectedDataIds, getRowId]);

  // Replace your useEffect hooks with this optimized version:

  // Sync row selection with selectedDataIds (one-way sync from props to state)
  useEffect(() => {
    if (!enableRowSelection || !setSelectedDataIds) return;

    const newSelection: RowSelectionState = {};
    data.forEach((row, index) => {
      if (selectedDataIds.has(getRowId(row))) {
        newSelection[index] = true;
      }
    });

    // Only update if there's an actual change to prevent loops
    if (JSON.stringify(newSelection) !== JSON.stringify(rowSelection)) {
      setRowSelection(newSelection);
    }
  }, [data, selectedDataIds, getRowId]); // Remove rowSelection from dependencies

  // Update selectedDataIds when row selection changes (one-way sync from state to props)
  useEffect(() => {
    if (!enableRowSelection || !setSelectedDataIds) return;

    const newSelectedIds = new Set<string>();
    Object.keys(rowSelection).forEach((index) => {
      if (rowSelection[parseInt(index)]) {
        const row = data[parseInt(index)];
        if (row) {
          newSelectedIds.add(getRowId(row));
        }
      }
    });

    // Only update if there's an actual change to prevent loops
    const currentIds = Array.from(selectedDataIds).sort().join(",");
    const newIds = Array.from(newSelectedIds).sort().join(",");

    if (currentIds !== newIds) {
      setSelectedDataIds(newSelectedIds);
    }
  }, [rowSelection, data, getRowId]); // Remove selectedDataIds and setSelectedDataIds from dependencies

  const handleRowChange = useCallback(
    (e: { value: string[] }) => {
      paginationProps?.setPageSize?.(Number(e.value[0]));
    },
    [paginationProps]
  );

  const handleExport = async () => {
    if (tableHeader?.downloadExportDataFunc) {
      const exportData = await tableHeader.downloadExportDataFunc();
      exportCSV(exportData, "exported-data");
      return;
    }
    exportCSV(data, "exported-data");
  };

  //  pagination helpers here
  const currentPage = paginationProps?.page ?? 1;
  const pageSize = paginationProps?.pageSize ?? 10;
  const total = paginationProps?.total ?? 0;
  const totalPages = Math.ceil(total / pageSize);

  const getPageNumbers = (current: number, total: number) => {
    const delta = 2; // how many pages before/after current
    const pages: number[] = [];
    for (
      let i = Math.max(1, current - delta);
      i <= Math.min(total, current + delta);
      i++
    ) {
      pages.push(i);
    }
    return pages;
  };

  const pageNumbers = getPageNumbers(currentPage, totalPages);

  return (
    <div className="flex flex-col w-full border-0">
      <TableHeader
        tableHeader={tableHeader}
        handleExport={handleExport}
        selectedCount={selectedDataIds.size}
        selectedData={selectedData}
        enableColumnVisibility={enableColumnVisibility}
        table={table}
      />
      <div className="overflow-x-auto rounded-md border bg-white h-full ">
        <Table className="min-w-full divide-y divide-gray-200">
          <TableHead className="bg-gray-50 sticky top-0 z-10">
            {table.getHeaderGroups().map((headerGroup) => (
              <tr key={headerGroup.id} className="bg-gray-50">
                {headerGroup.headers.map((header) => {
                  return (
                    <th
                      key={header.id}
                      className="px-4 py-3 text-center text-xs font-semibold text-gray-700 tracking-wider select-none"
                    >
                      <div className="flex items-center justify-start gap-1">
                        {header.id !== "select" &&
                          flexRender(
                            header.column.columnDef.header,
                            header.getContext()
                          )}
                      </div>
                    </th>
                  );
                })}
              </tr>
            ))}
          </TableHead>
          <TableBody className="bg-white divide-y divide-gray-200">
            {!isLoading ? (
              table.getRowModel().rows.length > 0 ? (
                table.getRowModel().rows.map((row) => (
                  <TableRow
                    key={row.id}
                    className={
                      expensesClickMode || onRowClick ? "cursor-pointer" : undefined
                    }
                    onClick={(e) => {
                      const target = e.target as HTMLElement;
                      // Ignore clicks on interactive elements
                      if (
                        target.closest(
                          'button, a, input, select, textarea, [role="menu"], [role="checkbox"], [data-prevent-row-click]'
                        )
                      ) {
                        return;
                      }
                      // Generic row click handler
                      if (onRowClick) {
                        onRowClick(row.original);
                        return;
                      }
                      if (!expensesClickMode) return;
                      const original: unknown = row.original as unknown;
                      // For personal expenses, use reportId (UUID); for company expenses, use id (numeric)
                      const id = expensesClickMode === "personal" ? original?.reportId : original?.reportId;
                      if (id) {
                      // For personal expenses:
                      // - Draft -> Edit page (/expenses/personal/[id]/edit)
                      // - Pending/Others -> Detail page (/expenses/personal/[id])
                      if (expensesClickMode === "personal") {
                        if (original?.status === "draft") {
                            router.push(`/expenses/personal/${id}/edit`);
                        } else {
                            router.push(`/expenses/personal/${id}`);
                        }
                      } else {
                        // Company expenses -> Detail page (/expenses/company/[id])
                        router.push(`/expenses/company/${id}?scope=${expensesScope}`);
                      }
                      }
                    }}
                  >
                    {row.getVisibleCells().map((cell) => (
                      <TableCell
                        key={cell.id}
                        className="px-4 py-2.5 whitespace-nowrap text-left text-[#181D27]"
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext()
                        )}
                      </TableCell>
                    ))}
                  </TableRow>
                ))
              ) : (
                <TableRow className="hover:bg-transparent">
                  <TableCell
                    colSpan={table.getVisibleFlatColumns().length}
                    className="text-center py-20 text-lg hover:bg-transparent"
                  >
                    Oops, No data available!!!
                  </TableCell>
                </TableRow>
              )
            ) : (
              // Skeleton Loading State
              Array.from({ length: 5 }).map((_, rowIndex) => (
                <TableRow key={`skeleton-row-${rowIndex}`} className="hover:bg-transparent">
                  {table.getVisibleFlatColumns().map((column, colIndex) => (
                    <TableCell key={`skeleton-cell-${rowIndex}-${colIndex}`} className="px-4 py-2.5">
                      <Skeleton className="h-4 w-full rounded" />
                    </TableCell>
                  ))}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>
      {paginationProps?.total ? (
        <>
          <div className="flex  md:flex-row items-center justify-between bg-gray-50 py-2 px-4 rounded-b-md w-full mt-[-6px]">
            <div className="flex items-center gap-2 w-full sm:w-auto mb-2 md:mb-0">
              <span className="text-sm text-gray-700 whitespace-nowrap">
                {total > 0 ? (
                  <>
                    Showing {(currentPage - 1) * pageSize + 1}-
                    {Math.min(currentPage * pageSize, total)} of {total} entries
                  </>
                ) : (
                  <>Showing 0 of 0 entries</>
                )}
              </span>
              <Select
                value={String(paginationProps.pageSize)}
                onValueChange={(value) => {
                  handleRowChange({ value: [value] });
                  paginationProps.setPage(1);
                }}
              >
                <SelectTrigger className="w-fit min-w-[80px]">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {PAGE_SIZE_OPTIONS.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      {option.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex w-full md:w-auto justify-end gap-2">
              <Pagination>
                <PaginationContent>
                  <PaginationItem>
                    <PaginationPrevious
                      onClick={(e) => {
                        e.preventDefault();
                        paginationProps.setPage(
                          Math.max(1, paginationProps.page - 1)
                        );
                      }}
                      href="#"
                      isDisabled={currentPage === 1}
                      isActive={currentPage > 1}
                      size={"sm"}
                    />
                  </PaginationItem>
                  {/* First page + Ellipsis */}
                  {pageNumbers[0] > 1 && (
                    <>
                      <PaginationItem>
                        <PaginationLink
                          onClick={(e) => {
                            e.preventDefault();
                            paginationProps.setPage(1);
                          }}
                          href="#"
                          isActive={1 === paginationProps.page}
                          size={"sm"}
                        >
                          1
                        </PaginationLink>
                      </PaginationItem>
                      {pageNumbers[0] > 2 && (
                        <PaginationItem>
                          <PaginationEllipsis />
                        </PaginationItem>
                      )}
                    </>
                  )}
                  <div className="hidden md:flex ">
                    {/* Visible page numbers */}
                    {pageNumbers.map((page) => (
                      <PaginationItem key={page}>
                        <PaginationLink
                          className={`${
                            paginationProps.page !== page
                              ? "text-muted-foreground"
                              : ""
                          }`}
                          onClick={(e) => {
                            e.preventDefault();
                            paginationProps.setPage(page);
                          }}
                          href="#"
                          isActive={page === paginationProps.page}
                          size={"sm"}
                        >
                          {page}
                        </PaginationLink>
                      </PaginationItem>
                    ))}

                    {/* Ellipsis + Last page */}
                    {pageNumbers[pageNumbers.length - 1] < totalPages && (
                      <>
                        {pageNumbers[pageNumbers.length - 1] <
                          totalPages - 1 && (
                          <PaginationItem>
                            <PaginationEllipsis />
                          </PaginationItem>
                        )}
                        <PaginationItem>
                          <PaginationLink
                            href="#"
                            size="sm"
                            isActive={totalPages === currentPage}
                            onClick={(e) => {
                              e.preventDefault();
                              paginationProps?.setPage(totalPages);
                            }}
                          >
                            {totalPages}
                          </PaginationLink>
                        </PaginationItem>
                      </>
                    )}
                  </div>
                  <div className="md:hidden block">
                    {/* Current Page - always visible */}
                    <PaginationItem>
                      <PaginationLink isActive size="sm" href={""}>
                        {paginationProps.page}
                      </PaginationLink>
                    </PaginationItem>
                  </div>
                  {/* Next */}
                  <PaginationItem>
                    <PaginationNext
                      onClick={(e) => {
                        e.preventDefault();
                        paginationProps.setPage(paginationProps.page + 1);
                      }}
                      href="#"
                      size={"sm"}
                      isActive={paginationProps.page < totalPages}
                      isDisabled={paginationProps.page === totalPages}
                    />
                  </PaginationItem>
                </PaginationContent>
              </Pagination>
            </div>
          </div>
        </>
      ) : null}
    </div>
  );
}

export { DataTable };

