            >
              {expense.status === "approved" && <CheckCircle2 size={12} />}
              {expense.status.charAt(0).toUpperCase() + expense.status.slice(1)}
            </span>
          </div>
        </div>
      </div>

      {/* Description */}
      <div className="detail-card col-span-2">
