        { label: "Mike Johnson", value: "mike" },
    ],
};

export function SplitExpense({ control, expenseIndex, totalAmount }: SplitExpenseProps) {
    const { fields, append, remove } = useFieldArray({
        control,
        name: `expenses.${expenseIndex}.splits`,
    });

    // Watch splits for this expense
    const watchedSplits = useWatch({
        control,
        name: `expenses.${expenseIndex}.splits`,
    });

    // Γ£à Debounce the totalAmount to avoid jitter when typing
    const [debouncedTotalAmount] = useDebounce(totalAmount, 300);

    // Γ£à Properly memoized calculations
    const { remainingAmount, splitTypes } = useMemo(() => {
        const splits = watchedSplits || [];
        const allocatedAmount = splits.reduce((sum: number, split: unknown) => {
            return sum + (parseFloat(split?.amount) || 0);
        }, 0);

        const types = splits.map((split: unknown) => split?.type || "department");

        return {
            remainingAmount: debouncedTotalAmount - allocatedAmount,
            splitTypes: types,
        };
    }, [watchedSplits, debouncedTotalAmount]);

    const addSplit = useCallback(() => {
        append({
            type: "department",
            option: null,
            amount: 0,
        });
    }, [append]);

    const removeSplit = useCallback((index: number) => {
        remove(index);
    }, [remove]);

    const getCurrencySymbol = useAuthStore((state) => state.getCurrencySymbol);
    const currencySymbol = getCurrencySymbol();
    return (
        <div className="space-y-4">
            <Button
                type="button"
                variant="link"
                disabled={remainingAmount <= 0}
                size="sm"
                onClick={addSplit}
                className="text-primary underline text-base font-bold leading-[150%] !p-0 disabled:bg-transparent disabled:text-primary/40"
            >
                Split Expense
            </Button>

            <div className="space-y-3">
                {fields.map((field, splitIndex) => (
                    <SplitItem
                        key={field.id}
                        control={control}
                        expenseIndex={expenseIndex}
                        splitIndex={splitIndex}
                        splitType={splitTypes[splitIndex] || "department"}
                        onRemove={() => removeSplit(splitIndex)}
                    />
                ))}

                {remainingAmount < 0 && (
                    <div className="text-sm text-destructive font-medium">
                        Total split amount exceeds expense amount by {currencySymbol}
                        {Math.abs(remainingAmount).toFixed(2)}
                    </div>
                )}
            </div>
        </div>
    );
}

// Γ£à SplitItem memoized to prevent unnecessary re-renders
const SplitItem = React.memo(
    ({
        control,
        expenseIndex,
        splitIndex,
        splitType,
        onRemove,
    }: {
        control: unknown;
        expenseIndex: number;
        splitIndex: number;
        splitType: string;
        onRemove: () => void;
    }) => {
        const getOptions = useCallback((type: string) => {
            return splitOptions[type as keyof typeof splitOptions] || [];
        }, []);

        return (
            <div className="border border-border rounded-lg p-3 space-y-3">
                <div className="flex justify-between items-center">
                    <Label className="text-sm font-medium">Split {splitIndex + 1}</Label>
                    <Button type="button" variant="ghost" size="sm" onClick={onRemove}>
                        <Trash className="h-4 w-4 text-destructive" />
                    </Button>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <FormFieldSelect
                        control={control}
                        name={`expenses.${expenseIndex}.splits.${splitIndex}.type`}
                        values={[
                            { label: "Department", value: "department" },
                            { label: "Category", value: "category" },
                            { label: "Project", value: "project" },
                            { label: "Colleagues", value: "colleagues" },
                        ]}
                        placeholder="Select Type"
                        label="Split Type"
                    />

                    <FormFieldSelect
                        control={control}
                        name={`expenses.${expenseIndex}.splits.${splitIndex}.option`}
                        values={getOptions(splitType)}
                        placeholder={`Select ${splitType}`}
                        label={`Select ${splitType}`}
                    />
                </div>

                <FormFieldInput
                    control={control}
                    name={`expenses.${expenseIndex}.splits.${splitIndex}.amount`}
                    label="Split Amount"
                    placeholder="Enter amount"
                    type="number"
                    inputMode="numeric"
                />
            </div>
        );
    }
);

"use client";

import { logger } from "@/lib/logger";
import React, { useState, useEffect } from "react";
import { useDataTable } from "@/components/datatable/useDataTable";
import { DataTable } from "@/components/datatable";
import { useDateFilterStore } from "@/stores/useDateFilterStore";
import type { ColumnDef } from "@tanstack/react-table";

import { useRouter } from "next/navigation";

const ExpenseTable = ({
  actionButton = <></>,
  statusFilter = null,
  data = [],
  onFilteredDataChange,
  columnsOverride,
  page = 1,
  scope,
}: {
  actionButton?: React.ReactElement;
  statusFilter?: string | null;
  data?: unknown[];
  onFilteredDataChange?: (filteredData: unknown[]) => void;
  columnsOverride?: ColumnDef<any, any>[];
  page?: number;
  scope?: string;
}) => {
  const router = useRouter();
  const [filteredData, setFilteredData] = useState(data);
  const [appliedFilters, setAppliedFilters] = useState<Record<string, string>>(
    {}
  );
  const { fromDate, toDate } = useDateFilterStore();

  const tableprops = useDataTable({
    initialPage: page,
    initialPageSize: 10,
    totalItems: data.length,
    manualSorting: false,
    manualFiltering: false,
    manualPagination: false,
  });
  const { globalSearch, setTotalItems } = tableprops;

  // Helper function to parse date strings
  const parseDate = (dateString: string): Date | null => {
    try {
      // Try parsing common formats
      const date = new Date(dateString);
      if (!isNaN(date.getTime())) {
        return date;
      }
      return null;
    } catch {
      return null;
    }
  };

  // Combine search and filter logic
  useEffect(() => {
    let filtered = [...data];

    // Apply status filter from tab
    if (statusFilter) {
      if (statusFilter === "pending") {
        filtered = filtered.filter((item) => item.status === "pending" || item.status === "pending_policy_check");
      } else {
        filtered = filtered.filter((item) => item.status === statusFilter);
      }
    }

    // Apply search filter
    if (globalSearch && globalSearch.trim() !== "") {
      const searchTerm = globalSearch.toLowerCase().trim();
      filtered = filtered.filter(
        (item) =>
          item.description?.toLowerCase().includes(searchTerm) ||
          item.employee?.toLowerCase().includes(searchTerm) ||
          item.category?.toLowerCase().includes(searchTerm) ||
          item.amount?.toString().includes(searchTerm) ||
          item.date?.toLowerCase().includes(searchTerm) ||
          item.status?.toLowerCase().includes(searchTerm)
      );
    }

    // Apply status filter from dropdown
    if (appliedFilters["filters[status]"]) {
      filtered = filtered.filter(
        (item) => item.status === appliedFilters["filters[status]"]
      );
    }

    // Apply category filter
    if (appliedFilters["filters[category]"]) {
      filtered = filtered.filter(
        (item) => item.category === appliedFilters["filters[category]"]
      );
    }

    // Apply date range filter from date picker
    if (fromDate && toDate) {
      filtered = filtered.filter((item) => {
        const itemDate = parseDate(item.date);
        if (!itemDate) return true; // Include items with invalid dates

        // Create date range (inclusive on both ends)
        const startOfDay = new Date(fromDate);
        startOfDay.setHours(0, 0, 0, 0);

        const endOfDay = new Date(toDate);
        endOfDay.setHours(23, 59, 59, 999);

        return itemDate >= startOfDay && itemDate <= endOfDay;
      });
    }

    setFilteredData(filtered);
    setTotalItems(filtered.length);

    // Notify parent component of filtered data changes
    if (onFilteredDataChange) {
      onFilteredDataChange(filtered);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [data, globalSearch, appliedFilters, statusFilter, fromDate, toDate]);

  return (
    <DataTable
      initialColumnVisibility={{ actions: false }}
      data={filteredData}
      columns={(columnsOverride ?? []) as unknown}
      paginationProps={tableprops.paginationProps}
      enableRowSelection={true}
      enableColumnVisibility={true}
      selectedDataIds={tableprops.selectedDataIds}
      setSelectedDataIds={tableprops.setSelectedDataIds}
      onRowClick={(row: unknown) => {
        // If scope is undefined, it's Personal Expenses.
        if (!scope) {
          const isDraft = row.status === "draft";
          const path = isDraft 
            ? `/expenses/personal/${row.reportId ?? row.id}/edit`
            : `/expenses/personal/${row.reportId ?? row.id}`;
          router.push(path);
        } else {
          // Company or Team scope
          router.push(`/expenses/company/${row.reportId ?? row.id}?scope=${scope}`);
        }
      }}
      tableHeader={{
        actionButton: actionButton,
        isSearchable: true,
        isExportable: false,
        isFilter: true,
        enableColumnVisibility: true,
        search: tableprops.globalSearch,
        searchQuery: tableprops.setGlobalSearch,
        filterProps: {
          title: "Reimbursements",
          filterData: [
            {
              name: "status",
              label: "Status",
              type: "select",
              options: [
                { label: "Pending", value: "pending" },
                { label: "Approved", value: "approved" },
                { label: "Declined", value: "declined" },
              ],
            },
            {
              name: "category",
              label: "Category",
              type: "select",
              options: [
                {
                  label: "Meals & Entertainment",
                  value: "Meals & Entertainment",
                },
                { label: "Transportation", value: "Transportation" },
                { label: "Office Supplies", value: "Office Supplies" },
                { label: "Travel", value: "Travel" },
                { label: "Software", value: "Software" },
              ],
            },
          ],
          onFilter: (filters: Record<string, unknown>) => {
            setAppliedFilters(filters as Record<string, string>);
          },
        },
        bulkActions: [
          {
            label: "Approve Selected",
            onClick: () => {
              logger.log(
                "Approving selected items:",
                Array.from(tableprops.selectedDataIds)
              );
            },
          },
          {
            label: "Decline Selected",
            onClick: () => {
              logger.log(
                "Declining selected items:",
                Array.from(tableprops.selectedDataIds)
              );
            },
          },
        ],
      }}
    />
  );
};

export default ExpenseTable;

