"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { useDropzone } from "react-dropzone";
import {
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "../ui/form";
import { Path } from "react-hook-form";
import { X, Upload, User } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "../ui/button";

interface FormFieldLogoUploadProps<T extends Record<string, unknown>> {
  control: unknown;
  name: Path<T>;
  label: string;
  description?: string;
  maxSize?: number;
  accept?: Record<string, string[]>;
  variant?: "default" | "button";
}

interface LogoUploadContentProps {
  value: File | string | undefined;
  onChange: (value: File | undefined) => void;
  maxSize: number;
  accept: Record<string, string[]>;
  variant?: "default" | "button";
}

const LogoUploadContent: React.FC<LogoUploadContentProps> = ({
  value,
  onChange,
  maxSize,
  accept,
  variant = "default",
}) => {
  const [previewUrl, setPreviewUrl] = useState<string | null>(() => {
    if (value instanceof File) {
      return URL.createObjectURL(value);
    } else if (typeof value === "string" && value) {
      return value;
    }
    return null;
  });
  const [error, setError] = useState<string | null>(null);

  // Sync preview with field value
  useEffect(() => {
    if (value instanceof File) {
      const url = URL.createObjectURL(value);
      setPreviewUrl(url);
      return () => URL.revokeObjectURL(url);
    } else if (typeof value === "string" && value) {
      setPreviewUrl(value);
    } else {
      setPreviewUrl(null);
    }
  }, [value]);

  const onDrop = useCallback(
    (acceptedFiles: File[], rejectedFiles: unknown[]) => {
      setError(null);

      if (rejectedFiles && rejectedFiles.length > 0) {
        const rejection = rejectedFiles[0];
        if (rejection.errors[0]?.code === "file-too-large") {
          setError(
            `File too large. Maximum ${Math.round(maxSize / 1024 / 1024)} MB.`
          );
        } else if (rejection.errors[0]?.code === "file-invalid-type") {
          setError(
            "Please upload a valid image file (PNG, JPG, JPEG, SVG, WEBP)."
          );
        } else {
          setError("File upload failed. Please try again.");
        }
        return;
      }

      if (!acceptedFiles || acceptedFiles.length === 0) {
        return;
      }

      const file = acceptedFiles[0];
      onChange(file);
    },
    [maxSize, onChange]
  );

  const { getRootProps, getInputProps, isDragActive, isDragReject, open } =
    useDropzone({
      onDrop,
      accept,
      maxSize,
      multiple: false,
      noClick: variant === "button", // Disable click on container for button variant
      noKeyboard: variant === "button",
    });

  const inputRef = useRef<HTMLInputElement>(null);

  const handleRemove = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (previewUrl && previewUrl.startsWith("blob:")) {
      URL.revokeObjectURL(previewUrl);
    }
    setPreviewUrl(null);
    onChange(undefined);
    setError(null);
  };

  if (variant === "button") {
      return (
          <div>
              <input {...getInputProps()} />
               <Button
                type="button"
                variant="outline"
                className="text-teal-500 border-teal-500 hover:text-teal-600 hover:border-teal-600 bg-transparent hover:bg-teal-50 flex items-center gap-2"
                onClick={open}
              >
                  {!value && <Upload className="w-4 h-4" />}
                  {value ? "Change Logo" : "Upload business logo"}
              </Button>
          </div>
      )
  }

  return (
    <div className="w-full">
      <div
        {...getRootProps()}
        className={cn(
          "border-2 border-dashed rounded-lg overflow-hidden text-center cursor-pointer transition-all duration-200 ease-in-out",
          isDragActive
            ? isDragReject
              ? "border-destructive bg-destructive/5"
              : "border-primary bg-primary/5"
            : "border-input bg-background hover:border-primary/50 hover:bg-accent/50"
        )}
      >
        <input ref={inputRef} {...getInputProps()} />
        {!previewUrl ? (
          <div className="flex flex-col items-center justify-center space-y-3 p-8 min-h-[200px]">
            <div className="flex items-center justify-center w-12 h-12 rounded-full bg-primary/10">
              <Upload className="w-6 h-6 text-primary" />
            </div>
            <div className="space-y-1">
              <p className="text-sm font-medium text-foreground">
                {isDragActive
                  ? isDragReject
                    ? "File type not supported"
                    : "Drop the logo here"
                  : "Drag & drop your business logo"}
              </p>
              <p className="text-xs text-muted-foreground">
                or click to browse
              </p>
              <p className="text-xs text-muted-foreground mt-2">
                PNG, JPG, JPEG, SVG, WEBP up to{" "}
                {Math.round(maxSize / 1024 / 1024)}MB
              </p>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center gap-4 p-8 min-h-[200px]">
            <div className="relative w-13 h-13 bg-muted rounded-lg overflow-hidden">
              <img
                src={previewUrl}
                alt="Business logo preview"
                className="w-full h-full object-contain place-self-center"
              />
            </div>
            <div className="flex gap-2">
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={(e) => {
                  e.stopPropagation();
                  inputRef.current?.click();
                }}
              >
                Change Logo
              </Button>
              <Button
                type="button"
                variant="outline"
                size="sm"
                onClick={handleRemove}
              >
                <X className="h-4 w-4" />
              </Button>
            </div>
          </div>
        )}
      </div>
      {error && (
        <div className="mt-2 flex items-center text-xs text-destructive bg-destructive/10 px-3 py-2 rounded-md">
          <span className="w-2 h-2 bg-destructive rounded-full mr-2"></span>
          {error}
        </div>
      )}
    </div>
  );
};

const FormFieldLogoUpload = <T extends Record<string, unknown>>({
  control,
  name,
  label,
  description,
  maxSize = 5 * 1024 * 1024, // 5MB default
  accept = { "image/*": [".png", ".jpg", ".jpeg", ".svg", ".webp"] },
  variant = "default", // Default to original behavior
}: FormFieldLogoUploadProps<T>) => {
  return (
    <FormField
      control={control}
      name={name}
      render={({ field }) => (
        <FormItem>
          {variant === "default" && <FormLabel>{label}</FormLabel>}
          <FormControl>
            {variant === "button" ? (
              // Compact Button Variant
              <div className="flex items-center gap-4">
                {/* Preview Circle / Placeholder */}
                {/* Preview Circle / Placeholder */}
                <div className={`relative w-16 h-16 rounded-full overflow-hidden flex-shrink-0 border border-gray-100 flex items-center justify-center ${field.value ? 'bg-transparent' : 'bg-teal-50'}`}>
                  {field.value ? (
                    <img
                      src={
                        (field.value as unknown) instanceof File
                          ? URL.createObjectURL(field.value as unknown)
                          : field.value as string
                      }
                      alt="Logo"
                      className="w-full h-full object-contain"
                    />
                  ) : (
                    <User className="w-8 h-8 text-black" />
                  )}
                </div>

                {/* Upload Button */}
                <LogoUploadContent
                  value={field.value}
                  onChange={field.onChange}
                  maxSize={maxSize}
                  accept={accept}
                  variant={variant}
                />
              </div>
            ) : (
              // Default Dropzone Variant
              <LogoUploadContent
                value={field.value}
                onChange={field.onChange}
                maxSize={maxSize}
                accept={accept}
              />
            )}
          </FormControl>
          {variant === "default" && description && <FormDescription>{description}</FormDescription>}
          <FormMessage />
        </FormItem>
      )}
    />
  );
};

export default FormFieldLogoUpload;

import React from 'react'
import { Dialog, DialogContent, DialogTitle, DialogDescription } from '../ui/dialog'
import { Button } from '../ui/button'

interface SuccessModalProps {
    isOpen: boolean
    onClose: () => void
    title: string
    description?: string
    buttonText?: string
    onClick?: () => void
}

const SuccessModal: React.FC<SuccessModalProps> = ({
    isOpen,
    onClose,
    title,
    description,
    buttonText = "Continue",
    onClick
}) => {
    const handleButtonClick = () => {
        if (onClick) {
            onClick()
        }
        onClose()
    }

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-md !rounded-[10px] !p-5">
                <DialogTitle className="sr-only">{title}</DialogTitle>
                <div className=" my-4 flex items-center justify-center">
                    <img
                        src={"/images/success.png"}
                        alt="success"
                        className="w-full h-auto max-h-36 object-contain animate-pulse"
                        loading='eager'
                    />
                </div>
                <div className="flex flex-col items-center text-center">

                    {/* Success Icon */}

                    <h3 className="text-xl font-semibold text-gray-900 mb-2">{title}</h3>
                    {description && <DialogDescription className="text-gray-600 mb-6">{description}</DialogDescription>}

                    <Button
                        onClick={handleButtonClick}
                        className="w-full"
                    >
                        {buttonText}
                    </Button>
                </div>
            </DialogContent>
        </Dialog>
    )
}

