import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Slider } from "@/components/ui/slider";
import { Checkbox } from "@/components/ui/checkbox";
import { X, Plus, AlertCircle } from "lucide-react";
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import FormFieldInput from "../form fields/formFieldInput";
import { Form } from "../ui/form";
import { zodResolver } from "@hookform/resolvers/zod";
import { getFormSchema } from "@/lib/schemas/schemas";
import z from "zod";
import { HugeiconsIcon } from "@hugeicons/react";
import { Briefcase01Icon, InformationCircleIcon, MailAtSign01Icon, User03FreeIcons, UserAdd01FreeIcons } from "@hugeicons/core-free-icons";
import { useAuthStore } from "@/stores/auth-stores";
import { useOnboardingStore } from "@/stores/useVilletoStore";

interface AddBeneficialOwnerModalProps {
    isOpen: boolean;
    onClose: () => void;
    onAdd: (owner: {
        firstName: string;
        lastName: string;
        role: string;
        email: string;
        ownershipPercentage?: number;
    }) => void;
    mode?: "beneficial" | "officer";
    editingPerson?: unknown;
    isOwner?: boolean;
}

export const AddBeneficialOwnerModal = ({
    isOpen,
    onClose,
    onAdd,
    mode = "beneficial",
    editingPerson,
    isOwner
}: AddBeneficialOwnerModalProps) => {
    const schema = getFormSchema(mode, isOwner);
    const isBeneficialOwner = mode === "beneficial" || isOwner;
    const currentUser = useAuthStore(s => s.user);
    const preOnboarding = useOnboardingStore(s => s.preOnboarding);
    const contactEmail = useOnboardingStore(s => s.contactEmail);

    const form = useForm({
        resolver: zodResolver(schema),
        defaultValues: {
            firstName: "",
            lastName: "",
            ...(isBeneficialOwner ? {} : { role: "" }),
            email: "",
            ownershipPercentage: undefined,
        }
    });
    const { handleSubmit, formState: { _errors }, setValue, watch, reset, control } = form;

    // "I'm also a beneficiary owner" checkbox state
    const [isSelf, setIsSelf] = useState(false);

    // compliance checkbox ΓÇö tracks whether ownership is capped at 25%
    const [complianceChecked, setComplianceChecked] = useState(true);

    const ownershipValue = watch("ownershipPercentage", undefined);
    const maxOwnership = complianceChecked ? 25 : 100;

    // When the "I'm also" checkbox is toggled ON, populate from current user or onboarding state
    const handleIsSelfChange = (checked: boolean) => {
        setIsSelf(checked);
        if (checked && (currentUser || preOnboarding || contactEmail)) {
            const fName = currentUser?.firstName || preOnboarding?.contactFirstName || "";
            const lName = currentUser?.lastName ? String(currentUser.lastName) : preOnboarding?.contactLastName || "";
            const email = currentUser?.email || preOnboarding?.contactEmail || contactEmail || "";

            setValue("firstName", fName, { shouldValidate: true });
            setValue("lastName", lName, { shouldValidate: true });
            setValue("email", email, { shouldValidate: true });
        } else if (!checked) {
            // Only clear if we haven't already started editing a different person
            if (!editingPerson) {
                setValue("firstName", "", { shouldValidate: false });
                setValue("lastName", "", { shouldValidate: false });
                setValue("email", "", { shouldValidate: false });
            }
        }
    };


    useEffect(() => {
        setIsSelf(false);
        if (editingPerson) {
            reset({
                firstName: editingPerson.firstName || "",
                lastName: editingPerson.lastName || "",
                ...(isBeneficialOwner ? {} : { role: editingPerson.role || editingPerson.villetoRole?.name || "" }),
                email: editingPerson.email || "",
                ownershipPercentage: editingPerson.ownershipPercentage || undefined,
            });
        } else {
            reset({
                firstName: "",
                lastName: "",
                ...(isBeneficialOwner ? {} : { role: "" }),
                email: "",
                ownershipPercentage: undefined,
            });
        }
    // `reset` is stable (react-hook-form guarantee) but listing it causes infinite loop ΓÇö intentionally omitted
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [editingPerson, isOpen]);

    const onSubmit = (data: z.infer<typeof schema>) => {
        if (isBeneficialOwner && (data.ownershipPercentage ?? 0) > maxOwnership) {
            return;
        }

        onAdd({
            firstName: data.firstName,
            lastName: data.lastName,
            role: isBeneficialOwner ? (isSelf ? "ORGANIZATION_OWNER" : "ORGANIZATION_OWNER") : (data as unknown).role ?? "",
            email: data.email,
            ownershipPercentage: data.ownershipPercentage
        });
        reset();
        setIsSelf(false);
    };

    const handleCancel = () => {
        onClose();
        reset();
        setIsSelf(false);
    };

    const handleOwnershipChange = (value: number[]) => {
        const capped = Math.min(value[0], maxOwnership);
        setValue("ownershipPercentage", capped, { shouldValidate: true });
    };

    const handleComplianceChange = (checked: boolean) => {
        setComplianceChecked(checked);
        // If switching to stricter cap and current value exceeds it, trim it
        if (checked && (ownershipValue ?? 0) > 25) {
            setValue("ownershipPercentage", 25, { shouldValidate: true });
        }
    };

    const isEditing = !!editingPerson;

    return (
        <Dialog open={isOpen} onOpenChange={handleCancel}>
            <DialogContent className="!sm:min-w-[600px] p-0 rounded-lg">
                <DialogHeader className="flex flex-row items-center justify-between space-y-0 p-6 pb-7 border-b border-b-muted">
                    <div className="flex items-center gap-2.5">
                        <div className="w-14 h-14 bg-muted/80 rounded-full flex items-center justify-center">
                            <HugeiconsIcon icon={UserAdd01FreeIcons} className="size-8 text-foreground" />
                        </div>
                        <div>
                            <DialogTitle className="text-xl leading-[100%] font-semibold">
                                {isEditing ? 'Edit' : 'Add'} {isBeneficialOwner ? 'Beneficial Owner' : 'Controlling Officer'}
                            </DialogTitle>
                            <p className="text-sm text-muted-foreground">
                                {isBeneficialOwner
                                    ? "Add beneficial owner by email address and assign role"
                                    : "Add company officer by email address and assign position"
                                }
                            </p>
                        </div>
                    </div>
                </DialogHeader>

                <Form {...form}>
                    <form onSubmit={handleSubmit(onSubmit)} className="space-y-5 p-5 pt-4">

                        {/* ΓöÇΓöÇ "I'm also a beneficiary owner" checkbox ΓöÇΓöÇ */}
                        {isBeneficialOwner && !isEditing && (
                            <div className={`flex items-start gap-3.5 p-4 rounded-xl border ${
                                isSelf ? "bg-primary/5 border-primary/30" : "bg-muted/30 border-muted-foreground/20"
                            }`}>
                                <Checkbox
                                    id="is-self"
                                    checked={isSelf}
                                    onCheckedChange={handleIsSelfChange}
                                    className="mt-0.5 shrink-0 cursor-pointer"
                                />
                                <div className="space-y-0.5">
                                    <Label htmlFor="is-self" className="text-sm font-semibold text-foreground cursor-pointer">
                                        I&apos;m also a beneficiary owner
                                    </Label>
                                    <p className="text-xs text-muted-foreground">
                                        This will auto-fill your details but you can add more owners.
                                    </p>
                                </div>
                            </div>
                        )}

                        {/* Name Fields */}
                        <div className="grid md:grid-cols-2 gap-6">
                            <FormFieldInput
                                name="firstName"
                                control={control}
                                placeholder="Enter first name"
                                label="First Name"
                                disabled={isSelf}
                                prefixIcon={
                                    <HugeiconsIcon icon={User03FreeIcons} className="size-4 text-muted-foreground" />
                                }
                            />
                            <FormFieldInput
                                name="lastName"
                                control={control}
                                placeholder="Enter last name"
                                label="Last Name"
                                disabled={isSelf}
                                prefixIcon={
                                    <HugeiconsIcon icon={User03FreeIcons} className="size-4 text-muted-foreground" />
                                }
                            />
                        </div>

                        {/* Role ΓÇö officer only */}
                        {!isBeneficialOwner && (
                            <FormFieldInput
                                control={control}
                                label="Role"
                                placeholder="Enter position"
                                name="role"
                                prefixIcon={
                                    <HugeiconsIcon icon={Briefcase01Icon} className="size-4 text-muted-foreground" />
                                }
                            />
                        )}

                        {/* Email */}
                        <>
                            <FormFieldInput
                                name="email"
                                control={control}
                                type="email"
                                placeholder="Enter email address"
                                label="Email Address"
                                disabled={isSelf}
                                prefixIcon={
                                    <HugeiconsIcon icon={MailAtSign01Icon} className="size-4 text-muted-foreground" />
                                }
                            />
                            {!isBeneficialOwner && (
                                <div className="flex gap-2 items-center">
                                    <HugeiconsIcon icon={InformationCircleIcon} className="size-5 text-primary" />
                                    <p className="text-xs text-black font-normal leading-[100%]">
                                        This email will be used to login to the company dashboard
                                    </p>
                                </div>
                            )}
                        </>

                        {/* Ownership Percentage */}
                        {isBeneficialOwner && (
                            <>
                                <div className="space-y-4">
                                    <div className="flex items-center justify-between">
                                        <Label className="text-sm font-medium">
                                            Percentage Ownership<span className="text-destructive">*</span>
                                        </Label>
                                        <span className={`font-semibold ${(ownershipValue ?? 0) > maxOwnership ? 'text-destructive' : 'text-primary'}`}>
                                            {ownershipValue ?? 0}%
                                            {(ownershipValue ?? 0) > maxOwnership && ` (Max ${maxOwnership}%)`}
                                        </span>
                                    </div>

                                    <Slider
                                        value={[(ownershipValue ?? 0)]}
                                        onValueChange={handleOwnershipChange}
                                        max={maxOwnership}
                                        step={1}
                                        className="w-full"
                                    />

                                    {(ownershipValue ?? 0) > maxOwnership && (
                                        <p className="text-destructive text-xs flex items-center gap-1">
                                            <AlertCircle className="h-3 w-3" />
                                            Ownership cannot exceed {maxOwnership}% to maintain compliance
                                        </p>
                                    )}
                                </div>

                                {/* Compliance Checkbox */}
                                <div
                                    className={`flex items-start space-x-3 p-4 rounded-lg cursor-pointer select-none transition-colors ${
                                        complianceChecked ? "bg-primary-light/20" : "bg-amber-50"
                                    }`}
                                    onClick={() => handleComplianceChange(!complianceChecked)}
                                >
                                    <Checkbox
                                        id="compliance"
                                        checked={complianceChecked}
                                        onCheckedChange={handleComplianceChange}
                                        className="mt-0.5"
                                        onClick={e => e.stopPropagation()}
                                    />
                                    <div className="space-y-1">
                                        <Label htmlFor="compliance" className="text-sm font-medium text-black cursor-pointer">
                                            No Single Owner holds 25% or more
                                        </Label>
                                        <p className="text-xs text-black">
                                            {complianceChecked
                                                ? "Checked ΓÇö ownership is capped at 25% for compliance"
                                                : "Unchecked ΓÇö ownership can go up to 100%"}
                                        </p>
                                    </div>
                                </div>
                            </>
                        )}

                        {/* Action Buttons */}
                        <div className="flex justify-between pt-6 gap-5">
                            <Button
                                type="button"
                                variant="ghostNavy"
                                onClick={handleCancel}
                                size="md"
                                className="flex items-center gap-2 flex-1"
                            >
                                Cancel
                                <X className="h-4 w-4" />
                            </Button>

                            <Button
                                type="submit"
                                size="md"
                                disabled={isBeneficialOwner && (ownershipValue ?? 0) > maxOwnership}
                                className="flex items-center gap-2 flex-1"
                            >
                                {isEditing ? 'Update' : 'Add'} {isBeneficialOwner ? 'Owner' : 'Controlling Officer'}
                                <Plus className="h-4 w-4" />
                            </Button>
                        </div>
                    </form>
                </Form>
            </DialogContent>
        </Dialog>
    );
};

"use client";

import { logger } from "@/lib/logger";
import React, { useCallback, useEffect, useState } from "react";
import { useDropzone } from "react-dropzone";

type UploadState = "idle" | "uploading" | "scanning" | "verified" | "failed";

function getMimeFromBase64(base64: string): string | null {
  const match = base64.match(/^data:(.+);base64,/);
  return match ? match[1] : null;
}
const extractFileType = (filename: string): string => {
  if (!filename) return 'unknown';

  // Get the file extension
  const extension = filename;

  // Map common image extensions to their MIME types
  const typeToExtension: Record<string, string> = {
    'image/jpeg': 'jpg',
    'image/png': 'png',
    'image/gif': 'gif',
    'image/webp': 'webp',
    'image/svg+xml': 'svg',
    'image/bmp': 'bmp',
    'image/x-icon': 'ico',
    'image/tiff': 'tiff'
  };

  return typeToExtension[extension] || 'application/octet-stream';
};
export default function FileUpload({
  accept = { "application/pdf": [".pdf"], "image/*": [".png", ".jpg", ".jpeg"] },
  maxSize = 10 * 1024 * 1024,
  onUploaded,
  _label,
  helper,
  originalUpload
}: {
  accept?: unknown;
  maxSize?: number;
  onUploaded?: (meta: { name: string; s3Key?: string; text?: string }) => void;
  label?: string;
  helper?: string;
  originalUpload: string | null
}) {
  const [_state, setState] = useState<UploadState>("idle");
  const [_progress, setProgress] = useState<number>(0);
  const [error, setError] = useState<string | null>(null);
  const [_filename, setFilename] = useState<string | null>(null);
  const [file, setFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);


  useEffect(() => {
    if (originalUpload) {
      logger.log(typeof originalUpload);
      logger.log({ originalUpload });

      // Directly set the base64 string as the preview URL
      setPreviewUrl(originalUpload);
      const mime = getMimeFromBase64(originalUpload)
      const filetype = extractFileType(mime!)
      logger.log({ mime }, { filetype })
      setFile(new File([originalUpload], `receipt.${filetype}`, {
        type: mime!
      }))

      // Simulate having a file when we have an originalUpload
      setFilename("preview-image.png");
      setState("verified");

      if (onUploaded) {
        onUploaded({ name: "preview-image.png" });
      }
    }
  }, [originalUpload]);
  const onDrop = useCallback(
    async (acceptedFiles: File[]) => {
      setError(null);
      logger.log
      if (!acceptedFiles || acceptedFiles.length === 0) {
        return;
      }

      const f = acceptedFiles[0];
      logger.log(f.size, { maxSize })
      if (f.size > maxSize) {
        setError(`File too large. Maximum ${Math.round(maxSize / 1024 / 1024)} MB.`);
        setState("failed");
        return;
      }

      // Create preview URL for images
      if (f.type.startsWith('image/')) {
        const url = URL.createObjectURL(f);
        setPreviewUrl(url);
      }

      setFile(f);
      setFilename(f.name);
      if (onUploaded) {

        onUploaded({ name: f.name });
      }

      try {

      } catch (_e: unknown) {
        setState("failed");
        setError("Failed scanning document.");
      }
    },
    [maxSize, onUploaded]
  );

  const { getRootProps, getInputProps, isDragActive, isDragReject } = useDropzone({
    onDrop,
    accept,
    maxSize,
    multiple: false
  });

  const _removeFile = () => {
    setFile(null);
    setFilename(null);
    setPreviewUrl(null);
    setState("idle");
    setProgress(0);
    setError(null);
    if (previewUrl) {
      URL.revokeObjectURL(previewUrl);
    }
  };

  const _formatFileSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };
  logger.log({ previewUrl })
  return (
    <div className="w-full h-full">
      {/* <div className="mb-3 flex items-center justify-between">
        <div className="text-base leading-[150%] font-semibold text-foreground">{label || "Upload File"}</div>
      </div> */}
      <div className="h-full max-h-[600px]">

        <div
          {...getRootProps()}
          className={`
              border-2 ${!file ? "border-dashed" : ""} rounded-lg overflow-hidden text-center cursor-pointer transition-all duration-200 ease-in-out h-full
              ${isDragActive
              ? isDragReject
                ? "border-red-400 bg-red-50"
                : "border-blue-400 bg-blue-50"
              : "border-gray-300 bg-gray-50 hover:border-gray-400 hover:bg-gray-100"
            }
              `}
        >
          <input {...getInputProps()} />
          {!file ? (

            <div className="flex flex-col items-center justify-center space-y-3 h-full">


              <p className="text-sm font-medium text-gray-700">
                {isDragActive
                  ? isDragReject
                    ? "File type not supported"
                    : "Drop the file here"
                  : "Drag & drop your file"}
              </p>
              <p className="text-xs text-gray-500">
                {helper || "PDF, JPG, PNG up to " + Math.round(maxSize / 1024 / 1024) + "MB"}
              </p>


            </div>
          ) : (
            <div className="">
              <div className="flex items-center space-x-3">
                {previewUrl && (
                  <div className="shrink-0 size-full object-contain rounded border overflow-auto">
                    {previewUrl}
                    <img
                      src={previewUrl}
                      alt="Preview"
                      className="w-full h-full object-contain overflow-y-auto rounded"
                    />
                  </div>
                  // ) : (
                  // <div className="flex-shrink-0 text-2xl">
                  //   {getFileIcon(filename!)}
                  // </div>
                  // )}
                )}
                {/* <div className="flex-grow min-w-0">
                  <div className="flex items-center justify-between">
                    <p className="text-sm font-medium text-gray-900 truncate">
                      {filename}
                    </p>
                    <button
                      onClick={removeFile}
                      className="text-gray-400 hover:text-gray-600 transition-colors"
                    >
                      Γ£ò
                    </button>
                  </div>
                  <p className="text-xs text-gray-500">
                    {formatFileSize(file.size)}
                  </p> */}

                {/* Progress Bar */}
                {/* {state === "uploading" || state === "scanning" ? (
                  <div className="mt-2 w-full bg-gray-200 rounded-full h-1.5">
                    <div
                      className="bg-blue-600 h-1.5 rounded-full transition-all duration-300"
                      style={{ width: `${progress}%` }}
                    />
                  </div>
                ) : state === "verified" ? (
                  <div className="mt-1 flex items-center text-xs text-green-600">
                    <span className="w-2 h-2 bg-green-600 rounded-full mr-1"></span>
                    Verified
                  </div>
                ) : null} */}

                {/* Status Text */}
                {/* <p className="text-xs text-gray-500 mt-1">
                  {state === "uploading" && "Uploading..."}
                  {state === "scanning" && "Scanning document..."}
                  {state === "verified" && "Document ready"}
                </p> */}
                {/* </div> */}
              </div>
            </div>
          )}
        </div>
      </div>
      {/* Error Display */}
      {maxSize && (
        <div className="mt-2 flex items-center text-xs font-normal text-muted-foreground ">

          Max. {maxSize / 1024 / 1024}mb
        </div>
      )}
      {/* Error Display */}
      {error && (
        <div className="mt-2 flex items-center text-xs text-red-600 bg-red-50 px-3 py-2 rounded-md">
          <span className="w-2 h-2 bg-red-600 rounded-full mr-2"></span>
          {error}
        </div>
      )}

      {/* Upload State Indicators */}
      {/* {state === "failed" && (
        <button
          onClick={removeFile}
          className="mt-2 text-sm text-blue-600 hover:text-blue-800 transition-colors"
        >
          Try again
        </button>
      )} */}
    </div>

  );
}

