"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useOnboardingStore } from "@/stores/useVilletoStore";

/**
 * Protects onboarding routes by checking for a valid onboardingId.
 * Redirects to /pre-onboarding if no onboardingId is found in the store.
 */
export default function OnboardingGuard({ children }: { children: React.ReactNode }) {
    const { onboardingId } = useOnboardingStore();
    const router = useRouter();
    const [isAuthorized, setIsAuthorized] = useState(false);

    useEffect(() => {
        if (!onboardingId) {
            router.replace("/pre-onboarding");
        } else {
            setIsAuthorized(true);
        }
    }, [onboardingId, router]);

    // Don't render children until we've confirmed authorization
    if (!isAuthorized) {
        return null;
    }

    return <>{children}</>;
}

"use client"

import { cn } from "@/lib/utils";
import { usePathname, useRouter } from "next/navigation";
import { useOnboardingStore } from "@/stores/useVilletoStore";

import { ONBOARDING_STEPS as steps } from "@/lib/constants/onboarding-steps";

const getInitials = (name: string) => {
  if (!name) return "";
  const words = name.trim().split(" ");
  if (words.length >= 2) {
    return (words[0][0] + words[1][0]).toUpperCase();
  }
  return name.substring(0, 2).toUpperCase();
};

export const OnboardingSidebar = () => {
    const pathName = usePathname();
    const router = useRouter();
    const { stoppedAtStep, businessSnapshot } = useOnboardingStore();

    // Filter out auto-generated names like "user@email.com Group"
    const isAutoGenerated = businessSnapshot.businessName?.includes("@");
    const displayBusinessName = isAutoGenerated ? "" : (businessSnapshot.businessName || "");

    // Compute currentStep once, outside the map
    const pathSegment = pathName?.split("/").pop();
    const isVerifyOtp = pathName?.includes('verify-otp');
    const currentStepObj = steps.find(s => s.key === pathSegment);
    let currentStep = currentStepObj?.id || 0;
    if (currentStep === 0 && isVerifyOtp) {
        currentStep = stoppedAtStep || 1;
    }
    const isStep3OrLater = currentStep >= 3;

    // Function to handle step click
    const handleStepClick = (stepKey: string, stepId: number) => {
        // Only navigate if the step is completed (stepId < currentStep)
        if (stepId < currentStep) {
            if (stepId == 1) {
                router.push(`/onboarding`);
                return;
            }
            router.push(`/onboarding/${stepKey}`);
        }
    };

    return (
        <div className="flex-1 max-w-[660px] h-full bg-contain bg-no-repeat rounded-[30px] relative overflow-hidden" style={{ backgroundImage: "url('/onboarding-layout.webp')" }}>

            <img src="/onboarding-layout.webp" className="h-full w-full rounded-[30px]" />
            {/* Overlay */}
            <div className="bg-navy/80 absolute p-8 top-0 bottom-0 left-0 right-0 w-full h-full flex flex-col rounded-[30px]">

                {/* Logo / Business branding ΓÇö rendered ONCE above the step list */}
                {isStep3OrLater ? (
                    <div className="mb-8 flex items-center gap-3">
                        {businessSnapshot.logo ? (
                            <img src={businessSnapshot.logo} alt="Company Logo" className="h-10 w-10 object-contain rounded-full bg-white border border-white/20" />
                        ) : (
                            <div className="h-10 w-10 flex items-center justify-center rounded-full bg-primary text-white font-semibold text-sm border border-white/20">
                                {getInitials(displayBusinessName)}
                            </div>
                        )}
                        <span className="text-white font-medium text-lg leading-tight truncate max-w-[200px]">
                            {displayBusinessName || "Your Business"}
                        </span>
                    </div>
                ) : (
                    <div className="mb-8">
                        <img src="/images/logo.png" className="h-16 w-40 object-cover" alt="Villeto Logo" />
                    </div>
                )}

                {/* Steps */}
                <div className="flex flex-col gap-1.5 flex-1">
                    {steps.map((step, index) => {
                        const isCurrent = step.key === pathSegment || (step.id === 1 && isVerifyOtp);
                        const isCompleted = step.id < currentStep && !isVerifyOtp;
                        const isUpcoming = currentStep + 1;

                        return (
                            <div key={step.id}>
                                <div
                                    className={cn(
                                        "flex items-start gap-5",
                                    {
                                        "cursor-pointer hover:opacity-80 transition-opacity": isCompleted,
                                        "cursor-default": !isCompleted
                                    }
                                )}
                                onClick={() => handleStepClick(step.key, step.id)}
                            >
                                {/* Step indicator */}
                                <div className="flex flex-col items-center gap-1.5">
                                    <div
                                        className={cn(
                                            "w-9 h-9 rounded-full flex items-center justify-center text-sm font-medium transition-colors border border-gray-600",
                                            {
                                                "bg-primary text-white border-0": isCompleted,
                                                "bg-transparent text-white border border-primary": isUpcoming === step.id || currentStep === step.id,
                                            }
                                        )}
                                    >
                                        <div className={cn("w-5 h-5 rounded-full bg-gray-600 border border-gray-600", {
                                            "bg-navy text-white": isCompleted,
                                            "bg-primary text-white border-primary border": (isUpcoming != step.id) && isCurrent,
                                        })} />
                                    </div>
                                    {/* Connector line */}
                                    {index < steps.length - 1 && (
                                        <div className="w-px h-9 bg-gray-500 mt-2" />
                                    )}
                                </div>

                                {/* Step content */}
                                <div className="flex-1 ">
                                    <div className="text-sm leading-[100%] text-white mb-2.5">
                                        STEP {step.id}
                                    </div>
                                    <div
                                        className={cn(
                                            "text-lg leading-[100%] font-semibold ",
                                            "text-white"
                                        )}
                                    >
                                        {step.title}
                                    </div>
                                </div>
                            </div>
                        </div>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

import { Building2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useOnboardingStore } from "@/stores/useVilletoStore";
import { HugeiconsIcon } from '@hugeicons/react';
import { LinkSquare01FreeIcons, BankIcon, Delete01Icon, PencilEdit02Icon, Link01Icon } from '@hugeicons/core-free-icons';
export const BankConnection = () => {
    const {
        bankConnected,
        bankProcessing,
        connectedAccounts,
        setShowConnectModal,
        removeConnectedAccount
    } = useOnboardingStore();

    const handleConnect = () => {
        setShowConnectModal(true);
    };

    const handleRemoveAccount = (id: string) => {
        removeConnectedAccount(id);
    };

    return (
        <div className="space-y-6">
            <div>
                <h3 className="text-lg font-normal leading-[100%] tracking-[0%] mb-2">
                    Bank Connection<span className="text-red-500">*</span>
                </h3>
            </div>

            {!bankConnected && connectedAccounts.length === 0 ? (
                // Initial state - not connected
                <div

                    className="w-full bg-[#FBFBFB] border border-[#D7D7D750] transition-colors duration-200  p-5 rounded-xl"
                >
                    <div className="flex items-start gap-3">
                        <HugeiconsIcon icon={BankIcon} className="w-5 h-5 text-villeto-gray mt-1" />
                        <div className="text-left">
                            <div className="font-normal tracking-[0%] leading-[100%] text-black text-base mb-1.5">Connect your bank</div>
                            <div className="text-[13px] tracking-[0%] leading-[100%] text-muted-foreground">View two ways to connect your bank</div>
                        </div>
                        <Button variant="ghost"
                            onClick={handleConnect} className="bg-gray-100 hover:bg-gray-200 text-black ml-auto" >
                            Connect
                            <HugeiconsIcon icon={LinkSquare01FreeIcons} className="size-4 text-black" />
                        </Button>
                    </div>
                </div>
            ) : (
                // Connected state
                <div className="space-y-4">
                    {/* Bank authorization status */}
                    {bankProcessing ? (
                        <div className="p-4 bg-amber-50 border border-amber-200 rounded-lg">
                            <div className="flex items-start gap-3">
                                <Building2 className="w-5 h-5 text-amber-600 mt-0.5" />
                                <div>
                                    <div className="font-medium text-amber-800">Bank Authorization</div>
                                    <div className="text-sm text-amber-700 mt-1">
                                        Your bank is processing the request to connect your bank account. You'll
                                        be notified when we have a response.
                                    </div>
                                </div>
                            </div>
                        </div>
                    ) : (
                        <div className="p-4 bg-green-50 border border-green-200 rounded-lg">
                            <div className="flex items-center gap-3">
                                <Building2 className="w-5 h-5 text-green-600" />
                                <div>
                                    <div className="font-medium text-green-800">Bank Authorization</div>
                                    <div className="text-sm text-green-700">Your bank authorized the connection!</div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Connected accounts */}
                    {connectedAccounts.map((account) => (
                        <div
                            key={account.id}
                            className="flex items-center gap-3 p-3 px-5 border border-[#D7D7D7] rounded-lg"
                        >
                            <div className="w-8 h-8 bg-villeto-light-gray rounded flex items-center justify-center">
                                <HugeiconsIcon icon={Link01Icon} className="w-4 h-4 text-black" />
                            </div>
                            <div className="flex-1">
                                <div className="font-normal tracking-[0%] leading-[100%] text-black">{account.url}</div>
                            </div>
                            <Button variant="ghost" size="sm" className="-10 h-10 rounded-full bg-muted">
                                <HugeiconsIcon icon={PencilEdit02Icon} className="w-4 h-4" />
                            </Button>
                            <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => handleRemoveAccount(account.id)}
                                className="text-gray hover:text-red-500 w-10 h-10 rounded-full bg-muted"
                            >
                                <HugeiconsIcon icon={Delete01Icon} className="w-4 h-4 text-red-500" />
                            </Button>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

import { useEffect } from "react";
import { useOnboardingStore } from "@/stores/useVilletoStore";
import { cn } from "@/lib/utils";
import { getCurrencyConfig } from "@/lib/utils/currency";

export const SpendingSlider = () => {
    const { monthlySpend, setMonthlySpend, businessSnapshot } = useOnboardingStore();
    const config = getCurrencyConfig(businessSnapshot.countryOfRegistration);
    const spendingRanges = config.spendingRanges;

    // Derive the displayed label from the current position + country config.
    // This ensures the correct currency label shows immediately when country changes,
    // without waiting for the slider to be moved.
    const displayLabel = spendingRanges[monthlySpend]?.label ?? spendingRanges[0].label;

    // Sync the store's spendRange whenever country or position changes so
    // downstream consumers (financial page, review page) always have the
    // correct currency label.
    useEffect(() => {
        setMonthlySpend(monthlySpend, spendingRanges[monthlySpend]?.label);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [businessSnapshot.countryOfRegistration]);

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h3 className="text-lg font-normal leading-[100%] tracking-[0%] text-black">
                        What's your team's expected monthly spend?
                        <span className="text-red-500">*</span>
                    </h3>
                </div>
                <div className="text-primary text-lg font-bold leading-[100%] tracking-[0%]">
                    {displayLabel}
                </div>
            </div>

            {/* Custom slider */}
            <div className="relative">
                {/* Track */}
                <div className="h-0.5 bg-gray-400 rounded-full relative">
                    {/* Active track */}
                    <div
                        className="h-1 bg-primary rounded-full transition-all duration-300"
                        style={{ width: `${(monthlySpend / 3) * 100}%` }}
                    />

                    {/* Slider thumb */}
                    <div
                        className="absolute top-1/2 -translate-y-1/2 w-6 h-6 bg-white rounded-full border-4 border-primary shadow-lg cursor-pointer transition-all duration-300"
                        style={{ left: `calc(${(monthlySpend / 3) * 100}% - 12px)` }}
                    />
                </div>

                {/* Range labels */}
                <div className="flex justify-between mt-4 text-sm text-villeto-gray">
                    {spendingRanges.map((range) => (
                        <button
                            key={range.value}
                            onClick={() => setMonthlySpend(range.value, range.label)}
                            className={cn(
                                "transition-colors duration-200",
                                monthlySpend === range.value ? "text-primary font-medium" : "hover:text-primary/80"
                            )}
                        >
                            {range.label}
                        </button>
                    ))}
                </div>

                {/* Hidden input for actual slider functionality */}
                <input
                    type="range"
                    min={0}
                    max={3}
                    step={1}
                    value={monthlySpend}
                    onChange={(e) => setMonthlySpend(parseInt(e.target.value), spendingRanges[parseInt(e.target.value)]?.label)}
                    className="absolute w-full h-8 -top-3 opacity-0 cursor-pointer z-10"
                />
            </div>
        </div>
    );
};

