function getRoleString(user: User | null): string {
  return (
    user?.villetoRole?.name?.toUpperCase() ||
    user?.position?.toUpperCase() ||
    ""
  );
}

function getFilteredSteps(
  user: User | null,
  can: (resource: string, action: string) => boolean
): TourStep[] {
  const roleStr = getRoleString(user);
  return ALL_STEPS.filter((step) => {
    if (step.roles?.length) {
      if (!step.roles.includes(roleStr)) return false;
    }
    if (step.requiredPermission) {
      const [resource, action] = step.requiredPermission.includes(".")
        ? (() => {
            const lastDot = step.requiredPermission.lastIndexOf(".");
            return [
              step.requiredPermission.substring(0, lastDot),
              step.requiredPermission.substring(lastDot + 1),
            ] as const;
          })()
        : (["", ""] as const);
      if (resource && action && !can(resource, action)) return false;
    }
    return true;
  });
}

// ΓöÇΓöÇΓöÇ SVG Spotlight overlay ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type SpotRect = { top: number; bottom: number; left: number; right: number };

function measureEl(selector: string): SpotRect | null {
  const el = document.querySelector<HTMLElement>(selector);
  if (!el) return null;
  const r = el.getBoundingClientRect();
  return { top: r.top, bottom: r.bottom, left: r.left, right: r.right };
}

function getSidebarWidth(): number {
  const el =
    document.querySelector<HTMLElement>('[data-sidebar="sidebar"]') ||
    document.querySelector<HTMLElement>("aside") ||
    document.querySelector<HTMLElement>('[class*="sidebar"]');
  return el ? el.getBoundingClientRect().width : 220;
}

function SpotlightOverlay({
  sidebarHref,
  targetSelector,
  targetIsInteractive,
  visible,
}: {
  sidebarHref?: string;
  targetSelector?: string;
  targetIsInteractive?: boolean;
  visible: boolean;
}) {
  const [vp, setVp] = useState({ w: 0, h: 0 });
  const [sidebarSpot, setSidebarSpot] = useState<
    (SpotRect & { sidebarW: number }) | null
  >(null);
  const [targetSpot, setTargetSpot] = useState<SpotRect | null>(null);

  const measure = useCallback(() => {
    setVp({ w: window.innerWidth, h: window.innerHeight });

    if (sidebarHref) {
      const el = document.querySelector<HTMLElement>(
        `a[href="${sidebarHref}"], [data-href="${sidebarHref}"]`
      );
      if (el) {
        const r = el.getBoundingClientRect();
        const sw = getSidebarWidth();
        setSidebarSpot({ top: r.top, bottom: r.bottom, left: 0, right: sw, sidebarW: sw });
      } else {
        setSidebarSpot(null);
      }
    } else {
      setSidebarSpot(null);
    }

    if (targetSelector) {
      setTargetSpot(measureEl(targetSelector));
    } else {
      setTargetSpot(null);
    }
  }, [sidebarHref, targetSelector]);

  // [FIX-1] Replace single requestAnimationFrame with a polling interval.
  // A one-shot rAF fires ~16ms after mount and never again, so after
  // client-side navigation the hole never re-measured and sat at the
  // wrong position until the next resize event.
  useEffect(() => {
    measure();
    const interval = setInterval(measure, 150);
    window.addEventListener("resize", measure);
    window.addEventListener("scroll", measure, true);
    return () => {
      clearInterval(interval);
      window.removeEventListener("resize", measure);
      window.removeEventListener("scroll", measure, true);
    };
  }, [measure]);

  if (vp.w === 0) return null;

  const { w, h } = vp;
  const SP = 6;
  const TP = 8;
  // Widen the target punch-out for the interactive account details section
  const TPA = targetIsInteractive ? 12 : TP;

  const outer = `M0 0 L${w} 0 L${w} ${h} L0 ${h}Z`;

  const sHole = sidebarSpot
    ? `M0 ${sidebarSpot.top - SP} L${sidebarSpot.sidebarW} ${sidebarSpot.top - SP} ` +
      `L${sidebarSpot.sidebarW} ${sidebarSpot.bottom + SP} L0 ${sidebarSpot.bottom + SP}Z`
    : "";

  const tHole = targetSpot
    ? `M${targetSpot.left - TPA} ${targetSpot.top - TPA} ` +
      `L${targetSpot.right + TPA} ${targetSpot.top - TPA} ` +
      `L${targetSpot.right + TPA} ${targetSpot.bottom + TPA} ` +
      `L${targetSpot.left - TPA} ${targetSpot.bottom + TPA}Z`
    : "";

  const d = [outer, sHole, tHole].filter(Boolean).join(" ");

  return (
    <svg
      aria-hidden
      style={{
        position: "fixed",
        inset: 0,
        width: "100%",
        height: "100%",
        zIndex: 9990,
        pointerEvents: "none",
        opacity: visible ? 1 : 0,
        transition: "opacity 0.35s ease",
      }}
    >
      <path fillRule="evenodd" d={d} fill="rgba(0,0,0,0.52)" />

      {sidebarSpot && (
        <rect
          x={0}
          y={sidebarSpot.top - SP}
          width={sidebarSpot.sidebarW}
          height={sidebarSpot.bottom - sidebarSpot.top + SP * 2}
          fill="none"
          stroke="rgba(13,148,136,0.8)"
          strokeWidth={2}
          rx={8}
          style={{ filter: "drop-shadow(0 0 6px rgba(13,148,136,0.55))" }}
        />
      )}

      {targetSpot && (
        <rect
          x={targetSpot.left - TPA}
          y={targetSpot.top - TPA}
          width={targetSpot.right - targetSpot.left + TPA * 2}
          height={targetSpot.bottom - targetSpot.top + TPA * 2}
          fill="none"
          stroke="rgba(13,148,136,0.8)"
          strokeWidth={2}
          rx={6}
          style={{ filter: "drop-shadow(0 0 6px rgba(13,148,136,0.55))" }}
        />
      )}
    </svg>
  );
}

// ΓöÇΓöÇΓöÇ Animated bouncing pointer arrow ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Auto-flips to the opposite side when the preferred placement would
// render off-screen (e.g. header buttons that sit at the very top).
// Arrow tip always points TOWARD the target element.

function PointerArrow({
  targetSelector,
  side = "top",
}: {
  targetSelector?: string;
  side?: ArrowSide;
}) {
  const [pos, setPos] = useState<{
    x: number;
    y: number;
    effectiveSide: ArrowSide;
  } | null>(null);

  const compute = useCallback(() => {
    if (!targetSelector || side === "none") { setPos(null); return; }
    const rect = measureEl(targetSelector);
    if (!rect) { setPos(null); return; }

    const TP  = 8;   // matches SpotlightOverlay padding
    const GAP = 30;  // distance from target edge to arrow centre
    const MIN = 50;  // min px from viewport edge for arrow to be visible
    const vw  = window.innerWidth;
    const vh  = window.innerHeight;

    let x = 0, y = 0, effectiveSide: ArrowSide = side;

    switch (side) {
      case "top": {
        const yAbove = rect.top - TP - GAP;
        if (yAbove > MIN) {
          y = yAbove; effectiveSide = "top";
        } else {
          // button too close to viewport top ΓÇö flip below
          y = rect.bottom + TP + GAP; effectiveSide = "bottom";
        }
        x = Math.min(Math.max((rect.left + rect.right) / 2, MIN), vw - MIN);
        break;
      }
      case "bottom": {
        const yBelow = rect.bottom + TP + GAP;
        if (yBelow < vh - MIN) {
          y = yBelow; effectiveSide = "bottom";
        } else {
          y = rect.top - TP - GAP; effectiveSide = "top";
        }
        x = Math.min(Math.max((rect.left + rect.right) / 2, MIN), vw - MIN);
        break;
      }
      case "left": {
        const xLeft = rect.left - TP - GAP;
        if (xLeft > MIN) {
          x = xLeft; effectiveSide = "left";
        } else {
          x = rect.right + TP + GAP; effectiveSide = "right";
        }
        y = Math.min(Math.max((rect.top + rect.bottom) / 2, MIN), vh - MIN);
        break;
      }
      case "right": {
        const xRight = rect.right + TP + GAP;
        if (xRight < vw - MIN) {
          x = xRight; effectiveSide = "right";
        } else {
          x = rect.left - TP - GAP; effectiveSide = "left";
        }
        y = Math.min(Math.max((rect.top + rect.bottom) / 2, MIN), vh - MIN);
        break;
      }
      default:
        setPos(null);
        return;
    }

    setPos({ x, y, effectiveSide });
  }, [targetSelector, side]);

  // [FIX-2] Replace single requestAnimationFrame with polling interval.
  useEffect(() => {
    compute();
    const interval = setInterval(compute, 150);
    window.addEventListener("resize", compute);
    window.addEventListener("scroll", compute, true);
    return () => {
      clearInterval(interval);
      window.removeEventListener("resize", compute);
      window.removeEventListener("scroll", compute, true);
    };
  }, [compute]);

  if (!pos || side === "none") return null;

  // Arrow tip faces TOWARD the target:
  // "top"    = arrow above target   ΓåÆ tip points Γåô (larger y = bottom of shape)
  // "bottom" = arrow below target   ΓåÆ tip points Γåæ (smaller y = top of shape)
  // "left"   = arrow left of target ΓåÆ tip points ΓåÆ (larger x = right of shape)
  // "right"  = arrow right of targetΓåÆ tip points ΓåÉ (smaller x = left of shape)
  const arrowPath = (s: ArrowSide): string => {
    switch (s) {
      case "top":    return "M0,14 L-11,-9 L0,-4 L11,-9 Z"; // Γåô tip at bottom
      case "bottom": return "M0,-14 L-11,9 L0,4 L11,9 Z";  // Γåæ tip at top
      case "left":   return "M14,0 L-9,-11 L-4,0 L-9,11 Z"; // ΓåÆ tip at right
      case "right":  return "M-14,0 L9,-11 L4,0 L9,11 Z";   // ΓåÉ tip at left
      default:       return "";
    }
  };

  const animName = `vta-${pos.effectiveSide}`;
  const dy = pos.effectiveSide === "top" ? 6 : pos.effectiveSide === "bottom" ? -6 : 0;
  const dx = pos.effectiveSide === "left" ? 6 : pos.effectiveSide === "right" ? -6 : 0;

  return (
    <svg
      aria-hidden
      style={{
        position: "fixed",
        inset: 0,
        width: "100%",
        height: "100%",
        zIndex: 9996,
        pointerEvents: "none",
        overflow: "visible",
      }}
    >
      <style>{`
        @keyframes ${animName}-kf {
          0%,100% { transform: translate(${pos.x}px, ${pos.y}px); }
          50%      { transform: translate(${pos.x + dx}px, ${pos.y + dy}px); }
        }
        .${animName}-arrow { animation: ${animName}-kf 1s ease-in-out infinite; }
      `}</style>
      <g className={`${animName}-arrow`}>
        <path
          d={arrowPath(pos.effectiveSide)}
          fill="#0d9488"
          stroke="white"
          strokeWidth="1.5"
          strokeLinejoin="round"
          style={{ filter: "drop-shadow(0 2px 8px rgba(13,148,136,0.7))" }}
        />
      </g>
    </svg>
  );
}

// ΓöÇΓöÇΓöÇ Tooltip position hook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type TooltipPos = {
  top?: number;
  left?: number;
  arrowLeft?: number;
  arrowTop?: number;
  placement: "near-target" | "center";
};

function useTooltipPosition(
  selector: string | undefined,
  arrowSide: ArrowSide = "none"
): TooltipPos {
  const [pos, setPos] = useState<TooltipPos>({ placement: "center" });

  const compute = useCallback(() => {
    if (!selector || arrowSide === "none") { setPos({ placement: "center" }); return; }
    const el = document.querySelector<HTMLElement>(selector);
    if (!el) { setPos({ placement: "center" }); return; }

    const rect = el.getBoundingClientRect();
    const CARD_W = 380;
    const GAP = 52;

    if (arrowSide === "top") {
      let left = rect.left + rect.width / 2 - CARD_W / 2;
      left = Math.max(12, Math.min(left, window.innerWidth - CARD_W - 12));
      setPos({ top: rect.bottom + GAP, left, arrowLeft: rect.left + rect.width / 2 - left, placement: "near-target" });
    } else if (arrowSide === "bottom") {
      let left = rect.left + rect.width / 2 - CARD_W / 2;
      left = Math.max(12, Math.min(left, window.innerWidth - CARD_W - 12));
      setPos({ top: rect.top - GAP - 400, left, arrowLeft: rect.left + rect.width / 2 - left, placement: "near-target" });
    } else if (arrowSide === "left") {
      let top = rect.top + rect.height / 2 - 100;
      top = Math.max(12, Math.min(top, window.innerHeight - 300));
      setPos({ top, left: rect.right + GAP + 10, arrowTop: rect.top + rect.height / 2 - top, placement: "near-target" });
    } else if (arrowSide === "right") {
      let top = rect.top + rect.height / 2 - 100;
      top = Math.max(12, Math.min(top, window.innerHeight - 300));
      setPos({ top, left: rect.left - CARD_W - GAP, arrowTop: rect.top + rect.height / 2 - top, placement: "near-target" });
    } else {
      setPos({ placement: "center" });
    }
  }, [selector, arrowSide]);

  // [FIX-3] Replace single requestAnimationFrame with polling interval and
  // add the missing scroll capture listener (SetupGuide had it, TourGuide didn't).
  useEffect(() => {
    compute();
    const interval = setInterval(compute, 150);
    window.addEventListener("resize", compute);
    window.addEventListener("scroll", compute, true);
    return () => {
      clearInterval(interval);
      window.removeEventListener("resize", compute);
      window.removeEventListener("scroll", compute, true);
    };
  }, [compute]);

  return pos;
}

// ΓöÇΓöÇΓöÇ WorkspaceProgress ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function WorkspaceProgress({
  steps,
  completedIds,
  total,
  done,
}: {
  steps: typeof PROGRESS_STEPS;
  completedIds: Set<string>;
  total: number;
  done: number;
}) {
  const pct = total > 1 ? Math.round((done / total) * 100) : 0;

  return (
    <div
      aria-label="Tour progress"
      style={{
        position: "fixed",
        bottom: 24,
        left: 24,
        zIndex: 10001,
        background: "white",
        borderRadius: 14,
        padding: "16px 20px",
        boxShadow: "0 4px 24px rgba(0,0,0,0.14), 0 1px 6px rgba(0,0,0,0.06)",
        border: "1px solid rgba(0,0,0,0.07)",
        minWidth: 220,
      }}
    >
      <p style={{ fontSize: 13, fontWeight: 600, color: "#111827", marginBottom: 8 }}>
        Workspace tour progress
      </p>

      <div style={{ height: 5, borderRadius: 99, background: "#e5f9f7", marginBottom: 4, overflow: "hidden" }}>
        <div
          style={{
            height: "100%",
            width: `${pct}%`,
            background: "linear-gradient(90deg,#2dd4bf,#0d9488)",
            borderRadius: 99,
            transition: "width 0.5s ease",
          }}
        />
      </div>

      <p style={{ fontSize: 10, color: "#6b7280", marginBottom: 10, textAlign: "right" }}>
        {done}/{total}
      </p>

      <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
        {steps.map(({ label, stepId }) => {
          const isDone = completedIds.has(stepId);
          return (
            <div key={stepId} style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div
                style={{
                  width: 16,
                  height: 16,
                  borderRadius: "50%",
                  border: `2px solid ${isDone ? "#0d9488" : "#d1d5db"}`,
                  background: isDone ? "#0d9488" : "white",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  flexShrink: 0,
                  transition: "all 0.3s ease",
                }}
              >
                {isDone && (
                  <svg width="8" height="8" viewBox="0 0 8 8" fill="none">
                    <path d="M1 4l2 2L7 2" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                  </svg>
                )}
              </div>
              <span
                style={{
                  fontSize: 12,
                  color: isDone ? "#9ca3af" : "#374151",
                  fontWeight: isDone ? 400 : 500,
                  textDecoration: isDone ? "line-through" : "none",
                }}
              >
                {label}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ TourCard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function TourCard({
  step,
  pos,
  visible,
  onPrimary,
  onSecondary,
  onClose,
}: {
  step: TourStep;
  pos: TooltipPos;
  visible: boolean;
  onPrimary: () => void;
  onSecondary: () => void;
  onClose: () => void;
}) {
  const headingId  = "tour-card-heading";
  const isCentered = pos.placement === "center";

  // [FIX-7] Focus the card when it becomes visible so keyboard users
  // can interact with it without having to tab to it manually.
  const cardRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (visible) {
      const t = setTimeout(() => cardRef.current?.focus(), 50);
      return () => clearTimeout(t);
    }
  }, [visible]);

  const wrapStyle: React.CSSProperties = isCentered
    ? {
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: visible
          ? "translate(-50%,-50%) scale(1)"
          : "translate(-50%,-50%) scale(0.94)",
        zIndex: 10000,
        width: 420,
        maxWidth: "calc(100vw - 32px)",
        opacity: visible ? 1 : 0,
        transition: "opacity 0.3s ease, transform 0.35s cubic-bezier(0.34,1.46,0.64,1)",
      }
    : {
        position: "fixed",
        top: pos.top,
        left: pos.left,
        zIndex: 10000,
        width: 380,
        maxWidth: "calc(100vw - 32px)",
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(-8px)",
        transition: "opacity 0.3s ease, transform 0.35s cubic-bezier(0.34,1.46,0.64,1)",
      };

  return (
    <div
      ref={cardRef}
      role="dialog"
      aria-modal="true"
      aria-labelledby={headingId}
      tabIndex={-1}
      style={{ ...wrapStyle, outline: "none" }}
    >
      {step.arrowSide === "top" && pos.arrowLeft !== undefined && (
        <div
          style={{
            position: "absolute",
            top: -10,
            left: pos.arrowLeft - 10,
            width: 0,
            height: 0,
            borderLeft: "10px solid transparent",
            borderRight: "10px solid transparent",
            borderBottom: "10px solid white",
            filter: "drop-shadow(0 -2px 3px rgba(0,0,0,0.07))",
            zIndex: 1,
          }}
        />
      )}

      {step.arrowSide === "left" && pos.arrowTop !== undefined && (
        <div
          style={{
            position: "absolute",
            top: (pos.arrowTop ?? 0) - 10,
            left: -10,
            width: 0,
            height: 0,
            borderTop: "10px solid transparent",
            borderBottom: "10px solid transparent",
            borderRight: "10px solid white",
            filter: "drop-shadow(-2px 0 3px rgba(0,0,0,0.07))",
            zIndex: 1,
          }}
        />
      )}

      <div
        style={{
          background: "white",
          borderRadius: 18,
          boxShadow: "0 24px 64px rgba(0,0,0,0.16), 0 4px 16px rgba(0,0,0,0.08)",
          overflow: "hidden",
          maxHeight: "calc(100vh - 100px)",
          display: "flex",
          flexDirection: "column",
        }}
      >
        <div style={{ padding: "28px 28px 24px", overflowY: "auto" }}>
          {/* Account details interactive hint */}
          {step.targetIsInteractive && (
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: 8,
                background: "#f0fdf9",
                border: "1px solid #a7f3d0",
                borderRadius: 8,
                padding: "7px 12px",
                marginBottom: 14,
              }}
            >
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                <circle cx="7" cy="7" r="6" stroke="#0d9488" strokeWidth="1.5" />
                <path d="M7 5v4M7 3.5v.5" stroke="#0d9488" strokeWidth="1.5" strokeLinecap="round" />
              </svg>
              <span style={{ fontSize: 11, color: "#065f46", fontWeight: 600 }}>
                This section is live ΓÇö you can fill it in right now!
              </span>
            </div>
          )}

          {/* Close */}
          <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 2 }}>
            <button
              onClick={onClose}
              aria-label="Skip tour"
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                padding: 4,
                borderRadius: 6,
                color: "#9ca3af",
                lineHeight: 1,
                transition: "color 0.2s",
              }}
              onMouseEnter={(e) =>
                ((e.currentTarget as HTMLButtonElement).style.color = "#374151")
              }
              onMouseLeave={(e) =>
                ((e.currentTarget as HTMLButtonElement).style.color = "#9ca3af")
              }
            >
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                <path d="M1 1l12 12M13 1L1 13" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
              </svg>
            </button>
          </div>

          <h2
            id={headingId}
            style={{ fontSize: 22, fontWeight: 700, color: "#111827", marginBottom: 12, letterSpacing: "-0.02em", lineHeight: 1.2 }}
          >
            {step.title}
          </h2>

          <p style={{ fontSize: 14, lineHeight: 1.7, color: "#4b5563", marginBottom: 28 }}>
            {step.description}
          </p>

          <div style={{ height: 1, background: "#f3f4f6", marginBottom: 20 }} />

          <div style={{ display: "flex", gap: 12 }}>
            {step.secondaryLabel && (
              <button
                onClick={onSecondary}
                style={{
                  flex: 1,
                  height: 44,
                  borderRadius: 10,
                  border: "1.5px solid #e5e7eb",
                  background: "white",
                  color: "#374151",
                  fontSize: 14,
                  fontWeight: 600,
                  cursor: "pointer",
                  transition: "border-color 0.2s",
                }}
                onMouseEnter={(e) =>
                  ((e.currentTarget as HTMLButtonElement).style.borderColor = "#0d9488")
                }
                onMouseLeave={(e) =>
                  ((e.currentTarget as HTMLButtonElement).style.borderColor = "#e5e7eb")
                }
              >
                {step.secondaryLabel}
              </button>
            )}

            <button
              onClick={onPrimary}
              style={{
                flex: 2,
                height: 44,
                borderRadius: 10,
                border: "none",
                background: "linear-gradient(135deg,#2dd4bf 0%,#0d9488 100%)",
                color: "white",
                fontSize: 14,
                fontWeight: 600,
                cursor: "pointer",
                boxShadow: "0 4px 14px rgba(13,148,136,0.35)",
                transition: "all 0.2s",
              }}
              onMouseEnter={(e) => {
                (e.currentTarget as HTMLButtonElement).style.transform = "translateY(-1px)";
                (e.currentTarget as HTMLButtonElement).style.boxShadow = "0 6px 18px rgba(13,148,136,0.45)";
              }}
              onMouseLeave={(e) => {
                (e.currentTarget as HTMLButtonElement).style.transform = "translateY(0)";
                (e.currentTarget as HTMLButtonElement).style.boxShadow = "0 4px 14px rgba(13,148,136,0.35)";
              }}
            >
              {step.primaryLabel}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Main Component ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export default function VilletoTourGuide() {
  const user          = useAuthStore((s) => s.user);
  const can = useAuthStore((s) => s.can);
  const router        = useRouter();
  const pathname      = usePathname();
  const searchParams  = useSearchParams();
  const setTourActive = useTourStore((s) => s.setTourActive);
  const setupGuideReady = useTourStore((s: unknown) => s.setupGuideReady ?? false);

  const [visible,      setVisible]      = useState(false);
  const [cardVisible,  setCardVisible]  = useState(false);
  const [stepIndex,    setStepIndex]    = useState(0);
  const [completedIds, setCompletedIds] = useState<Set<string>>(new Set());

  // ΓöÇΓöÇ alreadySeen ΓÇö reactive, localStorage-backed ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Using localStorage (not sessionStorage) so the flag survives browser
  // restarts on the same device. A separate effect auto-sets it when
  // loginCount > 1 so the tour never re-appears on subsequent logins,
  // including logins from a different device (as long as loginCount is
  // correctly incremented server-side via /users/me).
  const [alreadySeen, setAlreadySeen] = useState<boolean>(() => {
    if (typeof window === "undefined") return false;
    const key = user?.userId ? TOUR_KEY(user.userId) : null;
    return key ? localStorage.getItem(key) === "1" : false;
  });

  // ΓöÇΓöÇ [FIX-TDZ] Move derived keys, flags, and refs before the hooks that use them ΓöÇΓöÇ
  const mountLoginCountRef = useRef<number | null>(null);
  if (mountLoginCountRef.current === null && user !== null) {
    mountLoginCountRef.current =
      typeof user?.loginCount === "number" ? user.loginCount : -1;
  }

  const tourKey = user?.userId ? TOUR_KEY(user.userId) : null;

  // alreadySeen is reactive state (see useState above); do NOT re-read from
  // storage here ΓÇö the state is the single source of truth after hydration.

  // Use the login count that was in the store at mount time (frozen above).
  // This prevents the /users/me refresh from flipping isFirstLogin to false
  // after the 1500 ms start-tour timer has already been queued.
  const isFirstLogin =
    !!user &&
    mountLoginCountRef.current !== null &&
    mountLoginCountRef.current === 0;

  // Exclude only the company founder ΓÇö the CONTROLLING_OFFICER whose account
  // was created at the same moment as the company (createdAt timestamps match).
  const isCompanyFounder =
    user?.position === "CONTROLLING_OFFICER" &&
    !!user?.createdAt &&
    user.createdAt === user?.company?.createdAt;

  const shouldShow = isFirstLogin && !alreadySeen && !isCompanyFounder && setupGuideReady;

  // ΓöÇΓöÇ Auto-dismiss: loginCount > 1 means this is not a first login ΓöÇ
  // The login API sometimes returns loginCount=0 even for returning users;
  // /users/me (called in DashboardLayoutContent) returns the real value.
  // When the refreshed count is > 1 we mark the tour as seen in localStorage
  // so it is suppressed on this device and on any future session where the
  // login response also returns a stale 0.
  useEffect(() => {
    if (!user?.userId || !setupGuideReady) return;
    const lc = user.loginCount ?? 0;
    if (lc > 1 && tourKey) {
      if (localStorage.getItem(tourKey) !== "1") {
        localStorage.setItem(tourKey, "1");
      }
      setAlreadySeen(true); // triggers shouldShow ΓåÆ false ΓåÆ cancels the start timer
    }
  }, [user?.loginCount, user?.userId, setupGuideReady, tourKey]);


  const SETTLE_MS = 700;

  // pendingRef    ΓÇö nav-settle timer (card fade-in after page change)
  // advanceRef    ΓÇö step-advance timer (card fade-out + index increment)
  // stepIndexRef  ΓÇö live mirror of stepIndex so advance() never reads
  //                 a stale closure value (avoids stepIndex dep in useCallback)
  const pendingRef   = useRef<ReturnType<typeof setTimeout> | null>(null);
  const advanceRef   = useRef<ReturnType<typeof setTimeout> | null>(null);
  const stepIndexRef = useRef(0);

  const _roleStr = getRoleString(user);
  const steps   = getFilteredSteps(user, can);
  const step    = steps[stepIndex];

  // ΓöÇΓöÇ [FIX-5] Keep stepIndexRef in sync ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    stepIndexRef.current = stepIndex;
  }, [stepIndex]);

  // ΓöÇΓöÇ Cleanup all timers on unmount ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    return () => {
      if (pendingRef.current)  clearTimeout(pendingRef.current);
      if (advanceRef.current)  clearTimeout(advanceRef.current);
    };
  }, []);

  // ΓöÇΓöÇ Broadcast tour state ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    setTourActive(visible);
    return () => setTourActive(false);
  }, [visible, setTourActive]);


  // ΓöÇΓöÇ [FIX-4] Start tour ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  useEffect(() => {
    if (!shouldShow) return;
    const t1 = setTimeout(() => setVisible(true), 1500);
    const t2 = setTimeout(() => setCardVisible(true), 1550);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [shouldShow]);

  // ΓöÇΓöÇ [FIX-6] Navigation + card visibility ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // The original router.push branch returned undefined (no cleanup
  // registered), so if the effect re-ran before navigation resolved
  // the pending settle timer leaked. Now every branch registers cleanup.
  useEffect(() => {
    if (!visible || !step) return;
    if (pendingRef.current) clearTimeout(pendingRef.current);

    const targetUrl = step.navigateUrl ?? step.navigateTo;

    const tabMatch  = targetUrl.match(/tab=([^&]+)/);
    const targetTab = tabMatch ? tabMatch[1] : null;
    const currTab   = searchParams.get("tab");

    const isOnWrongPage = pathname !== step.navigateTo;
    const isOnWrongTab  = targetTab ? currTab !== targetTab : false;

    if (isOnWrongPage || isOnWrongTab) {
      router.push(targetUrl);
      return () => { if (pendingRef.current) clearTimeout(pendingRef.current); };
    }

    setCardVisible(false);
    pendingRef.current = setTimeout(() => setCardVisible(true), SETTLE_MS);
    return () => { if (pendingRef.current) clearTimeout(pendingRef.current); };
  }, [pathname, searchParams, stepIndex, visible]); // eslint-disable-line react-hooks/exhaustive-deps

  // ΓöÇΓöÇ Close tour ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const closeTour = useCallback(() => {
    if (!user) return;
    // Persist in localStorage (survives browser restarts on the same device)
    localStorage.setItem(TOUR_KEY(user.userId), "1");
    setAlreadySeen(true);
    setCardVisible(false);
    setTimeout(() => setVisible(false), 350);
  }, [user]);

  // ΓöÇΓöÇ [FIX-5] Advance step ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Read current index from ref so this callback never captures a stale
  // stepIndex from its closure ΓÇö stepIndex is no longer a dep, which also
  // means the keyboard effect no longer tears down and re-attaches its
  // listener on every step change.
  const advance = useCallback(() => {
    if (advanceRef.current) clearTimeout(advanceRef.current);
    setCardVisible(false);
    const cur = stepIndexRef.current;
    advanceRef.current = setTimeout(() => {
      const next = cur + 1;
      if (next >= steps.length) { closeTour(); return; }
      setCompletedIds((prev) => {
        const s = new Set(prev);
        // Mark current step complete using cur (not stepIndexRef ΓÇö by the time
        // this runs we want the step that was active when advance() was called).
        const currentStep = steps[cur];
        if (currentStep?.id) s.add(currentStep.id);
        return s;
      });
      setStepIndex(next);
    }, 280);
  }, [steps, closeTour]);

  // ΓöÇΓöÇ Account-details completion listener ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // VilletoSetupGuide uses custom window events to silently tick steps.
  // TourGuide must do the same for the account-details step so that when
  // the user saves their bank details (which dispatches
  // "villeto:account-details-saved" via notifySetupGuide), the tour
  // automatically marks that step complete and advances ΓÇö identical
  // behaviour to SetupGuide's markStepDone flow.
  useEffect(() => {
    if (!visible) return;
    const handler = () => {
      // Only act if the current step is account-details
      if (steps[stepIndexRef.current]?.id !== "account-details") return;
      // Fade card out, mark done, advance after short delay (mirrors advance())
      if (advanceRef.current) clearTimeout(advanceRef.current);
      setCardVisible(false);
      const cur = stepIndexRef.current;
      advanceRef.current = setTimeout(() => {
        const next = cur + 1;
        if (next >= steps.length) { closeTour(); return; }
        setCompletedIds((prev) => {
          const s = new Set(prev);
          s.add("account-details");
          return s;
        });
        setStepIndex(next);
      }, 800);
    };
    window.addEventListener("villeto:account-details-saved", handler);
    return () => window.removeEventListener("villeto:account-details-saved", handler);
  }, [visible, steps, closeTour]);

  // ΓöÇΓöÇ Primary CTA ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handlePrimary = useCallback(() => {
    if (step?.id === "setup-complete") {
      // Navigate to the new-report flow and close the tour.
      // This mirrors the SetupGuide BONUS_STEP: either the user clicks the
      // highlighted button directly (targetIsInteractive) or uses this CTA.
      router.push("/expenses/new-report");
      closeTour();
      return;
    }
    advance();
  }, [step, router, closeTour, advance]);

  // ΓöÇΓöÇ Secondary CTA ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const handleSecondary = useCallback(() => {
    if (step?.id === "setup-complete") {
      router.push("/dashboard");
      closeTour();
      return;
    }
    if (step?.secondaryLabel?.toLowerCase().includes("skip")) {
      closeTour();
      return;
    }
    advance();
  }, [step, router, advance, closeTour]);

  // ΓöÇΓöÇ [FIX-8] Keyboard ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Guard Enter: do NOT advance the tour when focus is inside a form
  // field ΓÇö this was swallowing keypresses in the interactive Account
  // Details step whenever the user pressed Enter to submit a form field.
  useEffect(() => {
    if (!visible) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") {
        closeTour();
        return;
      }
      if (e.key === "Enter") {
        const tag = (e.target as HTMLElement)?.tagName ?? "";
        if (tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT") return;
        handlePrimary();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [visible, handlePrimary, closeTour]);

  // ΓöÇΓöÇ Tooltip position ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const pos = useTooltipPosition(step?.targetSelector, step?.arrowSide ?? "none");

  // ΓöÇΓöÇ Progress tracker ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const progressList = PROGRESS_STEPS.filter((ps) =>
    steps.some((s) => s.id === ps.stepId)
  );
  const progressDone = progressList.filter((ps) => completedIds.has(ps.stepId)).length;

  if (!visible || !step || steps.length === 0) return null;

  const isWelcome = step.id === "welcome";

  return (
    <>
      {/*
       * Click-blocking layer.
       * Blocks all page interactions EXCEPT for the interactive target
       * element on steps where targetIsInteractive === true.
       * zIndex 9989 ΓÇö above content, below SVG overlay (9990).
       */}
      {step.targetIsInteractive ? (
        // For interactive steps: pointer-events:none so the underlying
        // interactive element is reachable through the overlay.
        <div
          aria-hidden
          style={{
            position: "fixed",
            inset: 0,
            zIndex: 9989,
            pointerEvents: "none",
            cursor: "default",
          }}
        />
      ) : (
        <div
          aria-hidden
          style={{
            position: "fixed",
            inset: 0,
            zIndex: 9989,
            pointerEvents: "all",
            cursor: "default",
          }}
          onClick={(e) => e.stopPropagation()}
          onMouseDown={(e) => e.stopPropagation()}
        />
      )}

      {/* Full-screen SVG spotlight overlay */}
      <SpotlightOverlay
        sidebarHref={isWelcome ? undefined : step.sidebarHref}
        targetSelector={isWelcome ? undefined : step.targetSelector}
        targetIsInteractive={step.targetIsInteractive}
        visible={cardVisible}
      />

      {/* Bouncing pointer arrow ΓÇö always rendered on top of overlay */}
      {!isWelcome && step.targetSelector && step.arrowSide && step.arrowSide !== "none" && (
        <PointerArrow
          targetSelector={step.targetSelector}
          side={step.arrowSide}
        />
      )}

      {/* Tour card */}
      <TourCard
        step={step}
        pos={pos}
        visible={cardVisible}
        onPrimary={handlePrimary}
        onSecondary={handleSecondary}
        onClose={closeTour}
      />

      {/* Workspace progress tracker */}
      {!isWelcome && progressList.length > 0 && (
        <WorkspaceProgress
          steps={progressList}
          completedIds={completedIds}
          total={progressList.length}
          done={progressDone}
        />
      )}
    </>
  );
}

"use client"

import * as React from "react"
import useEmblaCarousel, {
  type UseEmblaCarouselType,
} from "embla-carousel-react"
import { ArrowLeft, ArrowRight } from "lucide-react"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"

type CarouselApi = UseEmblaCarouselType[1]
type UseCarouselParameters = Parameters<typeof useEmblaCarousel>
type CarouselOptions = UseCarouselParameters[0]
type CarouselPlugin = UseCarouselParameters[1]

type CarouselProps = {
  opts?: CarouselOptions
  plugins?: CarouselPlugin
  orientation?: "horizontal" | "vertical"
  setApi?: (api: CarouselApi) => void
}

type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

const CarouselContext = React.createContext<CarouselContextProps | null>(null)

function useCarousel() {
  const context = React.useContext(CarouselContext)

  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }

  return context
}

const Carousel = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & CarouselProps
>(
  (
    {
      orientation = "horizontal",
      opts,
      setApi,
      plugins,
      className,
      children,
      ...props
    },
    ref
  ) => {
    const [carouselRef, api] = useEmblaCarousel(
      {
        ...opts,
        axis: orientation === "horizontal" ? "x" : "y",
      },
      plugins
    )
    const [canScrollPrev, setCanScrollPrev] = React.useState(false)
    const [canScrollNext, setCanScrollNext] = React.useState(false)

    const onSelect = React.useCallback((api: CarouselApi) => {
      if (!api) {
        return
      }

      setCanScrollPrev(api.canScrollPrev())
      setCanScrollNext(api.canScrollNext())
    }, [])

    const scrollPrev = React.useCallback(() => {
      api?.scrollPrev()
    }, [api])

    const scrollNext = React.useCallback(() => {
      api?.scrollNext()
    }, [api])

    const handleKeyDown = React.useCallback(
      (event: React.KeyboardEvent<HTMLDivElement>) => {
        if (event.key === "ArrowLeft") {
          event.preventDefault()
          scrollPrev()
        } else if (event.key === "ArrowRight") {
          event.preventDefault()
          scrollNext()
        }
      },
      [scrollPrev, scrollNext]
    )

    React.useEffect(() => {
      if (!api || !setApi) {
        return
      }

      setApi(api)
    }, [api, setApi])

    React.useEffect(() => {
      if (!api) {
        return
      }

      onSelect(api)
      api.on("reInit", onSelect)
      api.on("select", onSelect)

      return () => {
        api?.off("select", onSelect)
      }
    }, [api, onSelect])

    return (
      <CarouselContext.Provider
        value={{
          carouselRef,
          api: api,
          opts,
          orientation:
            orientation || (opts?.axis === "y" ? "vertical" : "horizontal"),
          scrollPrev,
          scrollNext,
          canScrollPrev,
          canScrollNext,
        }}
      >
        <div
          ref={ref}
          onKeyDownCapture={handleKeyDown}
          className={cn("relative", className)}
          role="region"
          aria-roledescription="carousel"
          {...props}
        >
          {children}
        </div>
      </CarouselContext.Provider>
    )
  }
)
Carousel.displayName = "Carousel"

const CarouselContent = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  const { carouselRef, orientation } = useCarousel()

  return (
    <div ref={carouselRef} className="overflow-hidden">
      <div
        ref={ref}
        className={cn(
          "flex",
          orientation === "horizontal" ? "-ml-4" : "-mt-4 flex-col",
          className
        )}
        {...props}
      />
    </div>
  )
})
CarouselContent.displayName = "CarouselContent"

const CarouselItem = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement>
>(({ className, ...props }, ref) => {
  const { orientation } = useCarousel()

  return (
    <div
      ref={ref}
      role="group"
      aria-roledescription="slide"
      className={cn(
        "min-w-0 shrink-0 grow-0 basis-full",
        orientation === "horizontal" ? "pl-4" : "pt-4",
        className
      )}
      {...props}
    />
  )
})
CarouselItem.displayName = "CarouselItem"

const CarouselPrevious = React.forwardRef<
  HTMLButtonElement,
  React.ComponentProps<typeof Button>
>(({ className, variant = "outline", size = "icon", ...props }, ref) => {
  const { orientation, scrollPrev, canScrollPrev } = useCarousel()

  return (
    <Button
      ref={ref}
      variant={variant}
      size={size}
      className={cn(
        "absolute  h-8 w-8 rounded-full",
        orientation === "horizontal"
          ? "-left-12 top-1/2 -translate-y-1/2"
          : "-top-12 left-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollPrev}
      onClick={scrollPrev}
      {...props}
    >
      <ArrowLeft className="h-4 w-4" />
      <span className="sr-only">Previous slide</span>
    </Button>
  )
})
CarouselPrevious.displayName = "CarouselPrevious"

const CarouselNext = React.forwardRef<
  HTMLButtonElement,
  React.ComponentProps<typeof Button>
>(({ className, variant = "outline", size = "icon", ...props }, ref) => {
  const { orientation, scrollNext, canScrollNext } = useCarousel()

  return (
    <Button
      ref={ref}
      variant={variant}
      size={size}
      className={cn(
        "absolute h-8 w-8 rounded-full",
        orientation === "horizontal"
          ? "-right-12 top-1/2 -translate-y-1/2"
          : "-bottom-12 left-1/2 -translate-x-1/2 rotate-90",
        className
      )}
      disabled={!canScrollNext}
      onClick={scrollNext}
      {...props}
    >
      <ArrowRight className="h-4 w-4" />
      <span className="sr-only">Next slide</span>
    </Button>
  )
})
CarouselNext.displayName = "CarouselNext"

export {
  type CarouselApi,
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselPrevious,
  CarouselNext,
}

